// calculateCurrentWorkload method static async calculateCurrentWorkload(staffId, semesterId) { try { // Get accepted assignments with all hours fields const acceptedAssignments = await query( `SELECT ca.*, c.credit_hours, c.lecture_hours, c.lab_hours, c.tutorial_hours, c.program_type FROM course_assignments ca LEFT JOIN courses c ON ca.course_id = c.course_id WHERE ca.staff_id = ? AND ca.semester_id = ? AND ca.status = 'accepted'`, [staffId, semesterId] ); // Calculate total hours using conversion factors let totalHours = 0; const assignedCourses = []; for (const assignment of acceptedAssignments) { // Convert hours to workload hours using standard factors const lectureHours = parseFloat(assignment.lecture_hours || 0) * 1.0; // Factor 1.0 const labHours = parseFloat(assignment.lab_hours || 0) * 0.75; // Factor 0.75 const tutorialHours = parseFloat(assignment.tutorial_hours || 0) * 0.5; // Factor 0.5 const courseLoad = lectureHours + labHours + tutorialHours; totalHours += courseLoad; assignedCourses.push({ course_id: assignment.course_id, course_code: assignment.course_code, credit_hours: assignment.credit_hours, lecture_hours: assignment.lecture_hours, lab_hours: assignment.lab_hours, tutorial_hours: assignment.tutorial_hours, program_type: assignment.program_type, estimated_load: courseLoad, }); } // Add existing workload RP hours const [workloadRP] = await query( `SELECT COALESCE(SUM(total_load), 0) as rp_hours FROM workload_rp WHERE staff_id = ? AND semester_id = ? AND status NOT IN ('rejected', 'draft')`, [staffId, semesterId] ); const rpHours = parseFloat(workloadRP.rp_hours || 0); totalHours += rpHours; return { total_hours: totalHours, assigned_courses: assignedCourses, assignment_count: acceptedAssignments.length, rp_hours: rpHours, }; } catch (error) { console.error("Calculate current workload error:", error); return { total_hours: 0, assigned_courses: [], assignment_count: 0, rp_hours: 0, }; } } import mysql from "mysql2/promise"; import bcrypt from "bcryptjs"; import env from "./env.js"; // Create pool connection const createPool = async () => { return mysql.createPool({ host: env.DB_HOST, port: env.DB_PORT, user: env.DB_USER, password: env.DB_PASSWORD, database: env.DB_NAME, waitForConnections: true, connectionLimit: 10, queueLimit: 0, enableKeepAlive: true, keepAliveInitialDelay: 0, }); }; let pool = null; // ============================================ // DATABASE INITIALIZATION - COMPLETE SETUP // ============================================ export const initializeDatabase = async () => { try { console.log("📦 Initializing SWOMS Database System..."); // First, create connection without database to create it const adminConnection = await mysql.createConnection({ host: env.DB_HOST, port: env.DB_PORT, user: env.DB_USER, password: env.DB_PASSWORD, }); // Create database if not exists await adminConnection.query(`CREATE DATABASE IF NOT EXISTS ${env.DB_NAME}`); console.log(`✅ Database '${env.DB_NAME}' ready`); // Switch to our database await adminConnection.query(`USE ${env.DB_NAME}`); // Create all tables in correct order await createAllTables(adminConnection); // Close admin connection await adminConnection.end(); // Now create the connection pool pool = await createPool(); // Insert minimal required data // await insertMinimalRequiredData(); console.log("🎉 Database initialization completed successfully!"); console.log(`📊 Database: ${env.DB_NAME}@${env.DB_HOST}:${env.DB_PORT}`); return true; } catch (error) { console.error("❌ Database initialization failed:", error.message); throw error; } }; // ============================================ // TABLE CREATION - ALL TABLES IN CORRECT ORDER // ============================================ const createAllTables = async (connection) => { console.log("🔧 Creating all database tables in correct order..."); // 1. USERS table (created first - no foreign keys) const usersTable = ` CREATE TABLE IF NOT EXISTS users ( user_id INT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(100) UNIQUE NOT NULL, email VARCHAR(150) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, role ENUM( 'admin', 'instructor', 'department_head', 'dean', 'cde_director', 'hr_director', 'vpaa', 'vpaf', 'finance', 'registrar' ) NOT NULL DEFAULT 'instructor', is_active BOOLEAN DEFAULT TRUE, last_login DATETIME, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, created_by INT, FOREIGN KEY (created_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 2. COLLEGES table (depends on users) const collegesTable = ` CREATE TABLE IF NOT EXISTS colleges ( college_id INT PRIMARY KEY AUTO_INCREMENT, college_code VARCHAR(20) UNIQUE NOT NULL, college_name VARCHAR(150) NOT NULL, dean_user_id INT, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (dean_user_id) REFERENCES users(user_id) ON DELETE SET NULL )`; // 3. DEPARTMENTS table (depends on colleges and users) const departmentsTable = ` CREATE TABLE IF NOT EXISTS departments ( department_id INT PRIMARY KEY AUTO_INCREMENT, department_code VARCHAR(20) UNIQUE NOT NULL, department_name VARCHAR(150) NOT NULL, college_id INT NOT NULL, head_user_id INT, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (college_id) REFERENCES colleges(college_id) ON DELETE CASCADE, FOREIGN KEY (head_user_id) REFERENCES users(user_id) ON DELETE SET NULL )`; // 4. STAFF PROFILES table (depends on users and departments) const staffProfilesTable = ` CREATE TABLE IF NOT EXISTS staff_profiles ( staff_id INT PRIMARY KEY AUTO_INCREMENT, user_id INT UNIQUE NOT NULL, employee_id VARCHAR(50) UNIQUE NOT NULL, first_name VARCHAR(100) NOT NULL, last_name VARCHAR(100) NOT NULL, middle_name VARCHAR(100), department_id INT NOT NULL, academic_rank ENUM( 'graduate_assistant', 'assistant_lecturer', 'lecturer', 'assistant_professor', 'associate_professor', 'professor' ) NOT NULL DEFAULT 'lecturer', employment_type ENUM('full_time', 'part_time', 'contract') DEFAULT 'full_time', hire_date DATE, phone VARCHAR(20), address TEXT, date_of_birth DATE, gender ENUM('male', 'female', 'other'), created_by INT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE CASCADE, FOREIGN KEY (created_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 5. ACADEMIC YEARS table (independent) const academicYearsTable = ` CREATE TABLE IF NOT EXISTS academic_years ( academic_year_id INT PRIMARY KEY AUTO_INCREMENT, year_code VARCHAR(20) UNIQUE NOT NULL, year_name VARCHAR(100) NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, is_active BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 6. SEMESTERS table (depends on academic_years) const semestersTable = ` CREATE TABLE IF NOT EXISTS semesters ( semester_id INT PRIMARY KEY AUTO_INCREMENT, academic_year_id INT NOT NULL, semester_code VARCHAR(20) UNIQUE NOT NULL, semester_name VARCHAR(50) NOT NULL, semester_type ENUM('semester_i', 'semester_ii', 'summer', 'distance', 'extension', 'weekend') NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, is_active BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (academic_year_id) REFERENCES academic_years(academic_year_id) ON DELETE CASCADE )`; // 7. PROGRAMS table (depends on departments) const programsTable = ` CREATE TABLE IF NOT EXISTS programs ( program_id INT PRIMARY KEY AUTO_INCREMENT, program_code VARCHAR(20) UNIQUE NOT NULL, program_name VARCHAR(150) NOT NULL, department_id INT NOT NULL, program_type ENUM('regular', 'extension', 'weekend', 'summer', 'distance') NOT NULL, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE CASCADE )`; // 8. COURSES table (depends on departments and programs) const coursesTable = ` CREATE TABLE IF NOT EXISTS courses ( course_id INT PRIMARY KEY AUTO_INCREMENT, course_code VARCHAR(20) UNIQUE NOT NULL, course_title VARCHAR(200) NOT NULL, department_id INT NOT NULL, program_id INT, academic_year INT, recommended_semester INT, course_order INT DEFAULT 0, credit_hours DECIMAL(4,2) NOT NULL, lecture_hours DECIMAL(4,2) NOT NULL, lab_hours DECIMAL(4,2) DEFAULT 0, tutorial_hours DECIMAL(4,2) DEFAULT 0, program_type ENUM('regular', 'extension', 'weekend', 'summer', 'distance') NOT NULL, course_year INT DEFAULT NULL COMMENT 'Year in curriculum (1-5)', course_semester INT DEFAULT NULL COMMENT 'Semester in curriculum (1 or 2)', is_core_course BOOLEAN DEFAULT TRUE, prerequisites VARCHAR(500), max_students INT DEFAULT 60, min_students INT DEFAULT 15, status ENUM('active', 'inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE CASCADE, FOREIGN KEY (program_id) REFERENCES programs(program_id) ON DELETE SET NULL )`; // 9. SECTIONS table (depends on courses, semesters, and staff_profiles) const sectionsTable = ` CREATE TABLE IF NOT EXISTS sections ( section_id INT PRIMARY KEY AUTO_INCREMENT, course_id INT NOT NULL, semester_id INT NOT NULL, section_code VARCHAR(20) NOT NULL, instructor_id INT, student_count INT DEFAULT 0, max_capacity INT DEFAULT 60, is_active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY unique_section (course_id, semester_id, section_code), FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (instructor_id) REFERENCES staff_profiles(staff_id) ON DELETE SET NULL )`; // 10. WORKLOAD RP table (depends on staff_profiles and semesters) - COMPLETE WITH ALL COLUMNS const workloadRpTable = ` CREATE TABLE IF NOT EXISTS workload_rp ( workload_id INT PRIMARY KEY AUTO_INCREMENT, staff_id INT NOT NULL, semester_id INT NOT NULL, -- Course Details (MANDATORY COLUMNS) course_code VARCHAR(50) NOT NULL, course_credit_hours DECIMAL(5,2) DEFAULT 0, lecture_credit_hours DECIMAL(5,2) DEFAULT 0, tutorial_credit_hours DECIMAL(5,2) DEFAULT 0, lab_credit_hours DECIMAL(5,2) DEFAULT 0, -- Student Details student_department VARCHAR(100), academic_year VARCHAR(50), number_of_sections INT DEFAULT 1, -- Load Calculation each_section_course_load DECIMAL(6,2) DEFAULT 0, variety_of_course_load DECIMAL(6,2) DEFAULT 0, research_load DECIMAL(6,2) DEFAULT 0, community_service_load DECIMAL(6,2) DEFAULT 0, -- Administrative & Other Loads elip_load DECIMAL(6,2) DEFAULT 0, hdp_load DECIMAL(6,2) DEFAULT 0, course_chair_load DECIMAL(6,2) DEFAULT 0, section_advisor_load DECIMAL(6,2) DEFAULT 0, advising_load DECIMAL(6,2) DEFAULT 0, position_load DECIMAL(6,2) DEFAULT 0, -- Summary total_load DECIMAL(6,2) NOT NULL DEFAULT 0, over_payment_birr DECIMAL(10,2) DEFAULT 0, -- Status and Metadata status ENUM( 'draft', 'submitted', 'dh_approved', 'dean_approved', 'hr_approved', 'vpaa_approved', 'vpaf_approved', 'finance_approved', 'rejected' ) DEFAULT 'draft', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, -- Foreign Keys FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, -- Indexes for better performance INDEX idx_staff_id (staff_id), INDEX idx_semester_id (semester_id), INDEX idx_status (status), INDEX idx_course_code (course_code) )`; // 11. WORKLOAD NRP table (depends on staff_profiles, semesters, and courses) - COMPLETE WITH ALL COLUMNS const workloadNrpTable = ` CREATE TABLE IF NOT EXISTS workload_nrp ( nrp_id INT PRIMARY KEY AUTO_INCREMENT, staff_id INT NOT NULL, semester_id INT NOT NULL, program_type ENUM('extension', 'weekend', 'summer', 'distance') NOT NULL, -- Basic Information contract_number VARCHAR(50), academic_year VARCHAR(50), academic_year_ec VARCHAR(50), contract_type ENUM('teaching', 'tutorial_correction', 'combined') DEFAULT 'teaching', -- Course Information course_id INT, course_code VARCHAR(50), course_title VARCHAR(200), -- Hours and Credit Information credit_hours DECIMAL(5,2) DEFAULT 0, lecture_credit_hours DECIMAL(5,2) DEFAULT 0, lab_credit_hours DECIMAL(5,2) DEFAULT 0, tutorial_credit_hours DECIMAL(5,2) DEFAULT 0, lecture_sections INT DEFAULT 0, lab_sections INT DEFAULT 0, tutorial_sessions INT DEFAULT 0, teaching_hours DECIMAL(6,2) DEFAULT 0, module_hours DECIMAL(6,2) DEFAULT 0, -- Student Information student_count INT DEFAULT 0, student_count_dept INT DEFAULT 0, student_count_year INT DEFAULT 0, student_count_section INT DEFAULT 0, assignment_students INT DEFAULT 0, exam_students INT DEFAULT 0, project_advising VARCHAR(255), project_groups INT DEFAULT 0, -- Rate Information rate_category ENUM('A', 'B', 'C', 'default'), rate_per_rank DECIMAL(10,2), assignment_rate DECIMAL(10,2) DEFAULT 25.00, exam_rate DECIMAL(10,2) DEFAULT 20.00, tutorial_rate_per_hour DECIMAL(10,2) DEFAULT 100.00, -- Payment Information teaching_payment DECIMAL(10,2) DEFAULT 0, tutorial_payment DECIMAL(10,2) DEFAULT 0, assignment_payment DECIMAL(10,2) DEFAULT 0, exam_payment DECIMAL(10,2) DEFAULT 0, project_payment DECIMAL(10,2) DEFAULT 0, total_payment DECIMAL(10,2) DEFAULT 0, total_hours_worked DECIMAL(6,2) DEFAULT 0, -- Contract Information contract_duration_from DATE, contract_duration_to DATE, -- Overload Information is_overload BOOLEAN DEFAULT FALSE, overload_hours DECIMAL(6,2) DEFAULT 0, overload_payment DECIMAL(10,2) DEFAULT 0, -- Status and Metadata status ENUM( 'draft', 'submitted', 'dh_approved', 'dean_approved', 'cde_approved', 'hr_approved', 'vpaf_approved', 'finance_approved', 'rejected', 'paid' ) DEFAULT 'draft', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, -- Foreign Keys FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE SET NULL, -- Indexes INDEX idx_nrp_staff_id (staff_id), INDEX idx_nrp_semester_id (semester_id), INDEX idx_nrp_program_type (program_type), INDEX idx_nrp_contract_number (contract_number) )`; // 12. PAYMENT SHEETS table (depends on workload_nrp and users) const paymentSheetsTable = ` CREATE TABLE IF NOT EXISTS payment_sheets ( payment_id INT PRIMARY KEY AUTO_INCREMENT, nrp_id INT, overload_id INT, payment_type ENUM('extension', 'weekend', 'summer', 'distance', 'overload') NOT NULL, sheet_number VARCHAR(50) UNIQUE NOT NULL, gross_amount DECIMAL(12,2) NOT NULL, tax_amount DECIMAL(12,2) DEFAULT 0, net_amount DECIMAL(12,2) NOT NULL, payment_status ENUM('pending', 'approved', 'paid', 'rejected') DEFAULT 'pending', approved_by INT, approved_date DATETIME, export_format ENUM('pdf', 'excel'), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (nrp_id) REFERENCES workload_nrp(nrp_id) ON DELETE SET NULL, FOREIGN KEY (approved_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 13. OVERLOAD PAYMENTS table (depends on staff_profiles and semesters) const overloadPaymentsTable = ` CREATE TABLE IF NOT EXISTS overload_payments ( overload_id INT PRIMARY KEY AUTO_INCREMENT, staff_id INT NOT NULL, semester_id INT NOT NULL, overload_hours DECIMAL(6,2) NOT NULL, rate_used DECIMAL(10,2) NOT NULL, gross_amount DECIMAL(12,2) NOT NULL, tax_amount DECIMAL(12,2) DEFAULT 0, net_amount DECIMAL(12,2) NOT NULL, payment_status ENUM('pending', 'approved', 'paid', 'rejected') DEFAULT 'pending', computed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, ruleset_version VARCHAR(20), FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE )`; // 14. TAX RULES table (independent) const taxRulesTable = ` CREATE TABLE IF NOT EXISTS tax_rules ( tax_id INT PRIMARY KEY AUTO_INCREMENT, program_type ENUM('extension', 'weekend', 'summer', 'distance', 'overload') NOT NULL, tax_rate DECIMAL(5,2) NOT NULL, effective_from DATE NOT NULL, effective_to DATE, description TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 15. RATE TABLES table (independent) const rateTablesTable = ` CREATE TABLE IF NOT EXISTS rate_tables ( rate_id INT PRIMARY KEY AUTO_INCREMENT, program_type ENUM('extension', 'weekend', 'summer', 'distance') NOT NULL, rate_category ENUM('A', 'B', 'C', 'default'), amount_per_credit DECIMAL(10,2), amount_per_hour DECIMAL(10,2), amount_per_student DECIMAL(10,2), effective_from DATE NOT NULL, effective_to DATE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 16. SYSTEM RULES table (independent) const systemRulesTable = ` CREATE TABLE IF NOT EXISTS system_rules ( rule_id INT PRIMARY KEY AUTO_INCREMENT, rule_name VARCHAR(100) NOT NULL, rule_value VARCHAR(255) NOT NULL, rule_type ENUM('load_factor', 'rank_limit', 'payment', 'distribution', 'other') NOT NULL, program_type VARCHAR(50), effective_from DATE NOT NULL, effective_to DATE, description TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY unique_rule (rule_name, effective_from) )`; // 17. RULESET HISTORY table (depends on users) const rulesetHistoryTable = ` CREATE TABLE IF NOT EXISTS ruleset_history ( history_id INT PRIMARY KEY AUTO_INCREMENT, rule_name VARCHAR(100) NOT NULL, previous_value VARCHAR(255), new_value VARCHAR(255) NOT NULL, changed_by INT, change_reason TEXT, effective_from DATE NOT NULL, effective_to DATE, program_type VARCHAR(50), version_number VARCHAR(20), changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (changed_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 18. SUMMER DISTRIBUTION table (independent) const summerDistributionTable = ` CREATE TABLE IF NOT EXISTS summer_distribution ( dist_id INT PRIMARY KEY AUTO_INCREMENT, stage1_percent DECIMAL(5,2) DEFAULT 30.00, stage2_percent DECIMAL(5,2) DEFAULT 30.00, stage3_percent DECIMAL(5,2) DEFAULT 20.00, stage4_percent DECIMAL(5,2) DEFAULT 20.00, effective_from DATE NOT NULL, effective_to DATE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP )`; // 19. APPROVAL WORKFLOW table (depends on users) const approvalWorkflowTable = ` CREATE TABLE IF NOT EXISTS approval_workflow ( approval_id INT PRIMARY KEY AUTO_INCREMENT, entity_type ENUM('workload_rp', 'workload_nrp', 'overload') NOT NULL, entity_id INT NOT NULL, approver_role VARCHAR(50) NOT NULL, approver_id INT, status ENUM('pending', 'approved', 'rejected', 'returned') DEFAULT 'pending', comments TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_entity (entity_type, entity_id), INDEX idx_approver (approver_role, status), FOREIGN KEY (approver_id) REFERENCES users(user_id) ON DELETE SET NULL )`; // 20. AUDIT LOG table (depends on users) const auditLogTable = ` CREATE TABLE IF NOT EXISTS audit_log ( audit_id INT PRIMARY KEY AUTO_INCREMENT, user_id INT NOT NULL, action VARCHAR(100) NOT NULL, entity VARCHAR(50) NOT NULL, entity_id INT, old_value TEXT, new_value TEXT, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP, ip_address VARCHAR(45), FOREIGN KEY (user_id) REFERENCES users(user_id) ON DELETE CASCADE )`; // 21. WORKLOAD DETAIL RP table (depends on workload_rp) const workloadDetailRpTable = ` CREATE TABLE IF NOT EXISTS workload_detail_rp ( detail_id INT PRIMARY KEY AUTO_INCREMENT, workload_id INT NOT NULL, detail_type ENUM('research', 'community', 'note') NOT NULL, description TEXT, hours DECIMAL(6,2) DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (workload_id) REFERENCES workload_rp(workload_id) ON DELETE CASCADE )`; // 22. NRP CONTRACT TEMPLATES table (depends on users) const nrpContractTemplatesTable = ` CREATE TABLE IF NOT EXISTS nrp_contract_templates ( template_id INT PRIMARY KEY AUTO_INCREMENT, template_name VARCHAR(100) NOT NULL, template_type VARCHAR(50), program_type VARCHAR(50), header_content TEXT, stipulation_content TEXT, table_structure JSON, signature_fields JSON, created_by INT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (created_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 23. NRP REPORTS table (depends on semesters, departments, colleges, users) const nrpReportsTable = ` CREATE TABLE IF NOT EXISTS nrp_reports ( report_id INT PRIMARY KEY AUTO_INCREMENT, report_type VARCHAR(50) NOT NULL, semester_id INT, department_id INT, college_id INT, report_period VARCHAR(100), generated_by INT NOT NULL, report_data JSON, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE SET NULL, FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE SET NULL, FOREIGN KEY (college_id) REFERENCES colleges(college_id) ON DELETE SET NULL, FOREIGN KEY (generated_by) REFERENCES users(user_id) ON DELETE CASCADE )`; // 24. COURSE ASSIGNMENTS table (depends on courses, semesters, staff_profiles, users) const courseAssignmentsTable = ` CREATE TABLE IF NOT EXISTS course_assignments ( assignment_id INT PRIMARY KEY AUTO_INCREMENT, course_id INT NOT NULL, semester_id INT NOT NULL, staff_id INT NOT NULL, student_year INT, assigned_by INT NOT NULL, section_code VARCHAR(20), assigned_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP, status ENUM('assigned', 'accepted', 'declined', 'withdrawn') DEFAULT 'assigned', notes TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY unique_course_assignment (course_id, semester_id, staff_id), FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (assigned_by) REFERENCES users(user_id) ON DELETE CASCADE )`; // 25. COURSE REQUESTS table (depends on courses, semesters, staff_profiles, users) const courseRequestsTable = ` CREATE TABLE IF NOT EXISTS course_requests ( request_id INT PRIMARY KEY AUTO_INCREMENT, course_id INT NOT NULL, semester_id INT NOT NULL, staff_id INT NOT NULL, requested_by INT NOT NULL, section_code VARCHAR(20), preferred_schedule VARCHAR(100), reason TEXT, status ENUM('pending', 'approved', 'rejected', 'cancelled') DEFAULT 'pending', processed_by INT, processed_date DATETIME, processed_notes TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE, FOREIGN KEY (semester_id) REFERENCES semesters(semester_id) ON DELETE CASCADE, FOREIGN KEY (staff_id) REFERENCES staff_profiles(staff_id) ON DELETE CASCADE, FOREIGN KEY (requested_by) REFERENCES users(user_id) ON DELETE CASCADE, FOREIGN KEY (processed_by) REFERENCES users(user_id) ON DELETE SET NULL )`; // 26. CURRICULUM PLANS table (depends on departments, programs, courses) const curriculumPlansTable = ` CREATE TABLE IF NOT EXISTS curriculum_plans ( plan_id INT PRIMARY KEY AUTO_INCREMENT, department_id INT NOT NULL, program_id INT, year INT NOT NULL COMMENT 'Academic year (1,2,3,4,5)', semester INT NOT NULL COMMENT 'Semester (1 or 2)', course_id INT NOT NULL, is_core BOOLEAN DEFAULT TRUE, is_elective BOOLEAN DEFAULT FALSE, prerequisites VARCHAR(500), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY unique_curriculum (department_id, program_id, year, semester, course_id), FOREIGN KEY (department_id) REFERENCES departments(department_id) ON DELETE CASCADE, FOREIGN KEY (program_id) REFERENCES programs(program_id) ON DELETE CASCADE, FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE )`; // Execute tables in correct order const tables = [ usersTable, collegesTable, departmentsTable, staffProfilesTable, academicYearsTable, semestersTable, programsTable, coursesTable, sectionsTable, workloadRpTable, workloadNrpTable, paymentSheetsTable, overloadPaymentsTable, taxRulesTable, rateTablesTable, systemRulesTable, rulesetHistoryTable, summerDistributionTable, approvalWorkflowTable, auditLogTable, workloadDetailRpTable, nrpContractTemplatesTable, nrpReportsTable, courseAssignmentsTable, courseRequestsTable, curriculumPlansTable, ]; for (let i = 0; i < tables.length; i++) { try { await connection.execute(tables[i]); console.log(`✓ Created table ${i + 1}/${tables.length}`); } catch (error) { console.error(`❌ Failed to create table ${i + 1}:`, error.message); throw error; } } }; // ============================================ // MINIMAL REQUIRED DATA INSERTION // ============================================ // const insertMinimalRequiredData = async () => { // console.log("📝 Inserting minimal required data..."); // try { // // Insert at least one admin user // const adminPasswordHash = await bcrypt.hash("admin123", 10); // await pool.execute( // `INSERT INTO users (username, email, password_hash, role, is_active, created_by) // VALUES (?, ?, ?, ?, TRUE, NULL)`, // ["admin", "admin@institution.edu", adminPasswordHash, "admin"] // ); // console.log("✓ Created admin user (username: admin, password: admin123)"); // console.log("✅ Minimal data inserted successfully"); // } catch (error) { // console.warn("⚠️ Could not insert minimal data:", error.message); // } // }; // ============================================ // EXACT DATA INSERTION FUNCTION // ============================================ // export const insertExactData = async (exactData = {}) => { // console.log("📝 Inserting exact data with proper relationships..."); // try { // if (!exactData || Object.keys(exactData).length === 0) { // console.log("⚠️ No data provided. Using minimal required data..."); // return; // } // // Insert data in correct order respecting foreign key relationships // const insertionOrder = [ // "users", // "colleges", // "departments", // "staff_profiles", // "academic_years", // "semesters", // "programs", // "courses", // "sections", // "workload_rp", // "workload_nrp", // "payment_sheets", // "overload_payments", // "tax_rules", // "rate_tables", // "system_rules", // "ruleset_history", // "summer_distribution", // "approval_workflow", // "audit_log", // "workload_detail_rp", // "nrp_contract_templates", // "nrp_reports", // "course_assignments", // "course_requests", // "curriculum_plans", // ]; // // Create mappings to track IDs for relationships // const idMaps = { // users: {}, // colleges: {}, // departments: {}, // staff_profiles: {}, // academic_years: {}, // semesters: {}, // programs: {}, // courses: {}, // }; // // Process each table in order // for (const tableName of insertionOrder) { // if (exactData[tableName] && exactData[tableName].length > 0) { // console.log(`📋 Inserting ${tableName}...`); // for (const record of exactData[tableName]) { // try { // // Process relationships before insertion // const processedRecord = await processRelationships( // tableName, // record, // idMaps // ); // // Insert the record // const [result] = await pool.execute( // buildInsertQuery(tableName, processedRecord) // ); // // Store the generated ID for future relationships // if (result.insertId) { // idMaps[tableName][ // record || record.original_id || result.insertId // ] = result.insertId; // } // console.log(` ✓ Inserted ${tableName} record`); // } catch (error) { // console.error( // ` ✗ Failed to insert ${tableName} record:`, // error.message // ); // throw error; // } // } // } // } // console.log( // "✅ Exact data inserted successfully with proper relationships!" // ); // } catch (error) { // console.error("❌ Failed to insert exact data:", error.message); // throw error; // } // }; // ============================================ // EXACT DATA INSERTION FUNCTION - WITHOUT TEMP_ID // ============================================ export const insertExactData = async (exactData = {}) => { console.log("📝 Inserting exact data with proper relationships..."); try { if (!exactData || Object.keys(exactData).length === 0) { console.log("⚠️ No data provided. Using minimal required data..."); return; } // Create mappings to track IDs for relationships const idMaps = { users: {}, colleges: {}, departments: {}, staff_profiles: {}, academic_years: {}, semesters: {}, programs: {}, courses: {}, sections: {}, workload_rp: {}, workload_nrp: {} }; // Insert users first (no dependencies) if (exactData.users && exactData.users.length > 0) { console.log(`📋 Inserting ${exactData.users.length} users...`); for (const record of exactData.users) { try { const processedRecord = { ...record }; // Remove fields that don't exist in the table delete processedRecord.created_by_username; // Build SQL query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => { const value = processedRecord[key]; if (typeof value === 'boolean') return value ? 1 : 0; if (value instanceof Date) return value.toISOString().split('T')[0]; return value; }); const sql = `INSERT INTO users (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by username if (result.insertId && record.username) { idMaps.users[record.username] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert user:`, error.message); console.error(` Record:`, record); throw error; } } } // Insert colleges (depends on users for dean_user_id) if (exactData.colleges && exactData.colleges.length > 0) { console.log(`📋 Inserting ${exactData.colleges.length} colleges...`); for (const record of exactData.colleges) { try { const processedRecord = { ...record }; // Handle dean_user_id relationship if (record.dean_username && idMaps.users[record.dean_username]) { processedRecord.dean_user_id = idMaps.users[record.dean_username]; } delete processedRecord.dean_username; // Build and execute query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => processedRecord[key]); const sql = `INSERT INTO colleges (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by college_code if (result.insertId && record.college_code) { idMaps.colleges[record.college_code] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert college:`, error.message); throw error; } } } // Insert departments (depends on colleges and users) if (exactData.departments && exactData.departments.length > 0) { console.log(`📋 Inserting ${exactData.departments.length} departments...`); for (const record of exactData.departments) { try { const processedRecord = { ...record }; // Handle relationships if (record.college_code && idMaps.colleges[record.college_code]) { processedRecord.college_id = idMaps.colleges[record.college_code]; } if (record.head_username && idMaps.users[record.head_username]) { processedRecord.head_user_id = idMaps.users[record.head_username]; } delete processedRecord.college_code; delete processedRecord.head_username; // Build and execute query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => processedRecord[key]); const sql = `INSERT INTO departments (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by department_code if (result.insertId && record.department_code) { idMaps.departments[record.department_code] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert department:`, error.message); throw error; } } } // Insert staff_profiles (depends on users and departments) if (exactData.staff_profiles && exactData.staff_profiles.length > 0) { console.log(`📋 Inserting ${exactData.staff_profiles.length} staff profiles...`); for (const record of exactData.staff_profiles) { try { const processedRecord = { ...record }; // Handle relationships if (record.username && idMaps.users[record.username]) { processedRecord.user_id = idMaps.users[record.username]; } if (record.department_code && idMaps.departments[record.department_code]) { processedRecord.department_id = idMaps.departments[record.department_code]; } if (record.created_by_username && idMaps.users[record.created_by_username]) { processedRecord.created_by = idMaps.users[record.created_by_username]; } delete processedRecord.username; delete processedRecord.department_code; delete processedRecord.created_by_username; // Build and execute query const columns = Object.keys(processedRecord).filter(key => processedRecord[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => processedRecord[key]); const sql = `INSERT INTO staff_profiles (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by employee_id (assuming it's unique) if (result.insertId && record.employee_id) { idMaps.staff_profiles[record.employee_id] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert staff profile:`, error.message); throw error; } } } // Insert academic_years (no dependencies) if (exactData.academic_years && exactData.academic_years.length > 0) { console.log(`📋 Inserting ${exactData.academic_years.length} academic years...`); for (const record of exactData.academic_years) { try { // Build and execute query const columns = Object.keys(record).filter(key => record[key] !== undefined ); const placeholders = columns.map(() => '?').join(', '); const values = columns.map(key => record[key]); const sql = `INSERT INTO academic_years (${columns.join(', ')}) VALUES (${placeholders})`; const [result] = await pool.execute(sql, values); // Store mapping by year_code if (result.insertId && record.year_code) { idMaps.academic_years[record.year_code] = result.insertId; } } catch (error) { console.error(`✗ Failed to insert academic year:`, error.message); throw error; } } } // Continue with other tables in dependency order... // Follow the same pattern for semesters, programs, courses, etc. console.log("✅ Exact data inserted successfully!"); return idMaps; // Return the ID mappings for debugging } catch (error) { console.error("❌ Failed to insert exact data:", error.message); throw error; } }; // Helper function to build INSERT query const buildInsertQuery = (tableName, record) => { const columns = Object.keys(record).join(", "); const placeholders = Object.keys(record) .map(() => "?") .join(", "); const values = Object.values(record); return `INSERT INTO ${tableName} (${columns}) VALUES (${placeholders})`; }; // Helper function to process relationships between tables const processRelationships = async (tableName, record, idMaps) => { const processedRecord = { ...record }; switch (tableName) { case "departments": if (record.college_code && idMaps.colleges[record.college_code]) { processedRecord.college_id = idMaps.colleges[record.college_code]; delete processedRecord.college_code; } if (record.head_username && idMaps.users[record.head_username]) { processedRecord.head_user_id = idMaps.users[record.head_username]; delete processedRecord.head_username; } break; case "staff_profiles": if (record.username && idMaps.users[record.username]) { processedRecord.user_id = idMaps.users[record.username]; delete processedRecord.username; } if ( record.department_code && idMaps.departments[record.department_code] ) { processedRecord.department_id = idMaps.departments[record.department_code]; delete processedRecord.department_code; } if ( record.created_by_username && idMaps.users[record.created_by_username] ) { processedRecord.created_by = idMaps.users[record.created_by_username]; delete processedRecord.created_by_username; } break; case "semesters": if (record.year_code && idMaps.academic_years[record.year_code]) { processedRecord.academic_year_id = idMaps.academic_years[record.year_code]; delete processedRecord.year_code; } break; case "programs": if ( record.department_code && idMaps.departments[record.department_code] ) { processedRecord.department_id = idMaps.departments[record.department_code]; delete processedRecord.department_code; } break; case "courses": if ( record.department_code && idMaps.departments[record.department_code] ) { processedRecord.department_id = idMaps.departments[record.department_code]; delete processedRecord.department_code; } if (record.program_code && idMaps.programs[record.program_code]) { processedRecord.program_id = idMaps.programs[record.program_code]; delete processedRecord.program_code; } break; case "course_assignments": if (record.course_code && idMaps.courses[record.course_code]) { processedRecord.course_id = idMaps.courses[record.course_code]; delete processedRecord.course_code; } if (record.semester_code && idMaps.semesters[record.semester_code]) { processedRecord.semester_id = idMaps.semesters[record.semester_code]; delete processedRecord.semester_code; } if ( record.staff_username && idMaps.staff_profiles[record.staff_username] ) { processedRecord.staff_id = idMaps.staff_profiles[record.staff_username]; delete processedRecord.staff_username; } if ( record.assigned_by_username && idMaps.users[record.assigned_by_username] ) { processedRecord.assigned_by = idMaps.users[record.assigned_by_username]; delete processedRecord.assigned_by_username; } break; case "course_requests": if (record.course_code && idMaps.courses[record.course_code]) { processedRecord.course_id = idMaps.courses[record.course_code]; delete processedRecord.course_code; } if (record.semester_code && idMaps.semesters[record.semester_code]) { processedRecord.semester_id = idMaps.semesters[record.semester_code]; delete processedRecord.semester_code; } if ( record.staff_username && idMaps.staff_profiles[record.staff_username] ) { processedRecord.staff_id = idMaps.staff_profiles[record.staff_username]; delete processedRecord.staff_username; } if ( record.requested_by_username && idMaps.users[record.requested_by_username] ) { processedRecord.requested_by = idMaps.users[record.requested_by_username]; delete processedRecord.requested_by_username; } break; } return processedRecord; }; // ============================================ // DATABASE UTILITY FUNCTIONS // ============================================ export const query = async (sql, params = []) => { if (!pool) { throw new Error( "Database pool not initialized. Call initializeDatabase() first." ); } try { // Convert undefined values to null for MySQL const processedParams = params.map((param) => { if (param === undefined) { return null; } return param; }); const [results] = await pool.execute(sql, processedParams); return results; } catch (error) { console.error("Database query error:", error.message); console.error("SQL:", sql); console.error("Params:", params); throw error; } }; // Get a connection from pool export const getConnection = async () => { if (!pool) { throw new Error( "Database pool not initialized. Call initializeDatabase() first." ); } return await pool.getConnection(); }; // Test database connection export const testConnection = async () => { try { const connection = await getConnection(); const [result] = await connection.execute("SELECT 1 + 1 AS test"); connection.release(); console.log("✅ Database connection test successful"); return result[0].test === 2; } catch (error) { console.error("❌ Database connection test failed:", error.message); return false; } }; // Get database statistics export const getDatabaseStats = async () => { try { const stats = {}; // Get table counts const tables = [ "users", "colleges", "departments", "staff_profiles", "academic_years", "semesters", "programs", "courses", "sections", "workload_rp", "workload_nrp", "payment_sheets", "overload_payments", "tax_rules", "rate_tables", "system_rules", "ruleset_history", "summer_distribution", "approval_workflow", "audit_log", "workload_detail_rp", "nrp_contract_templates", "nrp_reports", "course_assignments", "course_requests", "curriculum_plans", ]; for (const table of tables) { try { const [result] = await query(`SELECT COUNT(*) as count FROM ${table}`); stats[table] = result[0].count; } catch (err) { stats[table] = 0; } } return stats; } catch (error) { console.error("Error getting database stats:", error.message); return null; } }; // Check if database is initialized export const isDatabaseInitialized = async () => { try { const [result] = await query( `SELECT COUNT(*) as table_count FROM information_schema.tables WHERE table_schema = ?`, [env.DB_NAME] ); return result[0].table_count > 0; } catch (error) { return false; } }; // ============================================ // LOAD ALL TEST DATA FUNCTION // ============================================ export const loadAllTestData = async () => { try { console.log("📚 Loading complete test data for all API testing..."); // Import and use the AllData module const { insertTestData } = await import("./AllData.js"); // Wrap insertExactData to pass to AllData const wrappedInsertExactData = async (data) => { await insertExactData(data); }; await insertTestData(wrappedInsertExactData); console.log("✅ All test data loaded successfully!"); console.log("🎯 You can now test all API endpoints with complete relational data"); return true; } catch (error) { console.error("❌ Failed to load test data:", error.message); throw error; } }; // Export the pool export { pool }; import OverloadDetectionService from "../services/OverloadDetectionService.js"; import StaffModel from "../models/StaffModel.js"; import { sendSuccess, sendError } from "../utils/response.js"; import { query } from "../config/database.js"; class OverloadDetectionController { // Check staff overload static async checkStaffOverload(req, res) { try { const { staffId, semesterId } = req.params; const user_id = req.user.user_id; const user_role = req.user.role; // Validate permissions if (user_role === "instructor") { const staff = await StaffModel.findByUserId(user_id); if (staff.staff_id !== parseInt(staffId)) { return sendError( res, "You can only check your own overload status", 403 ); } } else if (user_role === "department_head") { const headStaff = await StaffModel.findByUserId(user_id); const targetStaff = await StaffModel.findById(parseInt(staffId)); if (headStaff.department_id !== targetStaff.department_id) { return sendError( res, "You can only check overload for staff in your department", 403 ); } } else if (!["admin", "hr_director", "dean"].includes(user_role)) { return sendError( res, "You are not authorized to check overload status", 403 ); } const overloadReport = await OverloadDetectionService.detectStaffOverload( parseInt(staffId), parseInt(semesterId) ); return sendSuccess(res, "Overload check completed", overloadReport); } catch (error) { console.error("Check staff overload error:", error); return sendError(res, error.message || "Failed to check overload", 500); } } // Check department overload static async checkDepartmentOverload(req, res) { try { const { departmentId, semesterId } = req.params; const user_id = req.user.user_id; const user_role = req.user.role; // Validate permissions if (user_role === "department_head") { const headStaff = await StaffModel.findByUserId(user_id); if (headStaff.department_id !== parseInt(departmentId)) { return sendError( res, "You can only check overload for your own department", 403 ); } } else if (!["admin", "hr_director", "dean"].includes(user_role)) { return sendError( res, "You are not authorized to check department overload", 403 ); } const departmentReport = await OverloadDetectionService.detectDepartmentOverload( parseInt(departmentId), parseInt(semesterId) ); return sendSuccess( res, "Department overload check completed", departmentReport ); } catch (error) { console.error("Check department overload error:", error); return sendError( res, error.message || "Failed to check department overload", 500 ); } } // Check my overload (for instructors) static async checkMyOverload(req, res) { try { const user_id = req.user.user_id; const { semester_id } = req.query; // Get staff profile const staff = await StaffModel.findByUserId(user_id); if (!staff) { return sendError(res, "Staff profile not found", 404); } // Get current semester if not specified let targetSemesterId = semester_id; if (!targetSemesterId) { const [currentSemester] = await query( "SELECT semester_id FROM semesters WHERE is_active = TRUE LIMIT 1" ); targetSemesterId = currentSemester?.semester_id; } if (!targetSemesterId) { return sendError(res, "No active semester found", 404); } const overloadReport = await OverloadDetectionService.detectStaffOverload( staff.staff_id, targetSemesterId ); return sendSuccess(res, "Your overload status retrieved", overloadReport); } catch (error) { console.error("Check my overload error:", error); return sendError( res, error.message || "Failed to check your overload status", 500 ); } } // Predict overload trend static async predictOverloadTrend(req, res) { try { const { staffId } = req.params; const { upcoming_semester_id } = req.body; const user_id = req.user.user_id; const user_role = req.user.role; if (!upcoming_semester_id) { return sendError(res, "Upcoming semester ID is required", 400); } // Validate permissions if (user_role === "instructor") { const staff = await StaffModel.findByUserId(user_id); if (staff.staff_id !== parseInt(staffId)) { return sendError( res, "You can only predict your own overload trend", 403 ); } } else if (user_role === "department_head") { const headStaff = await StaffModel.findByUserId(user_id); const targetStaff = await StaffModel.findById(parseInt(staffId)); if (headStaff.department_id !== targetStaff.department_id) { return sendError( res, "You can only predict overload for staff in your department", 403 ); } } else if (!["admin", "hr_director", "dean"].includes(user_role)) { return sendError( res, "You are not authorized to predict overload trends", 403 ); } const trendPrediction = await OverloadDetectionService.predictOverloadTrend( parseInt(staffId), parseInt(upcoming_semester_id) ); return sendSuccess( res, "Overload trend prediction completed", trendPrediction ); } catch (error) { console.error("Predict overload trend error:", error); return sendError( res, error.message || "Failed to predict overload trend", 500 ); } } // Generate overload report for approval static async generateOverloadReport(req, res) { try { const { staffId, semesterId } = req.params; const user_id = req.user.user_id; const user_role = req.user.role; // Only department heads, HR, and admins can generate reports if (!["admin", "hr_director", "department_head"].includes(user_role)) { return sendError( res, "You are not authorized to generate overload reports", 403 ); } if (user_role === "department_head") { const headStaff = await StaffModel.findByUserId(user_id); const targetStaff = await StaffModel.findById(parseInt(staffId)); if (headStaff.department_id !== targetStaff.department_id) { return sendError( res, "You can only generate reports for staff in your department", 403 ); } } const report = await OverloadDetectionService.generateOverloadReport( parseInt(staffId), parseInt(semesterId) ); // Store report in database if (report.requires_report) { await query( `INSERT INTO nrp_reports (report_type, semester_id, department_id, generated_by, report_data) VALUES ('overload_detection', ?, ?, ?, ?)`, [ parseInt(semesterId), report.data.department_id, user_id, JSON.stringify(report), ] ); } return sendSuccess(res, "Overload report generated", report); } catch (error) { console.error("Generate overload report error:", error); return sendError( res, error.message || "Failed to generate overload report", 500 ); } } // Get overload alerts (for department heads and admins) static async getOverloadAlerts(req, res) { try { const user_id = req.user.user_id; const user_role = req.user.role; const { department_id, threshold = 80 } = req.query; let targetDepartmentId = department_id; // For department heads, use their department if (user_role === "department_head") { const headStaff = await StaffModel.findByUserId(user_id); if (headStaff) { targetDepartmentId = headStaff.department_id; } } // Get active semester const [currentSemester] = await query( "SELECT semester_id FROM semesters WHERE is_active = TRUE LIMIT 1" ); if (!currentSemester) { return sendError(res, "No active semester found", 404); } // Get staff with high load const alerts = []; // Get department staff let staffQuery = "SELECT sp.staff_id, sp.first_name, sp.last_name, sp.employee_id, sp.academic_rank"; const params = []; if (targetDepartmentId) { staffQuery += " FROM staff_profiles sp WHERE sp.department_id = ?"; params.push(targetDepartmentId); } else { staffQuery += " FROM staff_profiles sp"; } const staffList = await query(staffQuery, params); // Check each staff member for (const staff of staffList) { const workload = await OverloadDetectionService.calculateTotalWorkload( staff.staff_id, currentSemester.semester_id ); const rankLimits = await OverloadDetectionService.getRankLimits( staff.academic_rank ); const loadPercentage = (workload.total_hours / rankLimits.max) * 100; if (loadPercentage >= threshold) { alerts.push({ staff_id: staff.staff_id, name: `${staff.first_name} ${staff.last_name}`, employee_id: staff.employee_id, academic_rank: staff.academic_rank, current_hours: workload.total_hours, max_hours: rankLimits.max, load_percentage: parseFloat(loadPercentage.toFixed(1)), status: OverloadDetectionService.getLoadStatus( workload.total_hours, rankLimits ), is_overloaded: workload.total_hours > rankLimits.max, overload_hours: Math.max(0, workload.total_hours - rankLimits.max), priority: this.getAlertPriority(loadPercentage), }); } } // Sort by priority (highest first) alerts.sort((a, b) => b.priority - a.priority); return sendSuccess(res, "Overload alerts retrieved", { semester_id: currentSemester.semester_id, department_id: targetDepartmentId, threshold: threshold, total_staff: staffList.length, alert_count: alerts.length, alerts: alerts, }); } catch (error) { console.error("Get overload alerts error:", error); return sendError(res, "Failed to get overload alerts", 500); } } // Get alert priority static getAlertPriority(loadPercentage) { if (loadPercentage >= 150) return 5; // Critical if (loadPercentage >= 120) return 4; // High if (loadPercentage >= 100) return 3; // Medium if (loadPercentage >= 90) return 2; // Low return 1; // Warning } } export default OverloadDetectionController; import RulesModel from "../models/RulesModel.js"; import { sendSuccess, sendError } from "../utils/response.js"; import { RULE_TYPES, PROGRAM_TYPES, ACADEMIC_RANKS } from "../config/constants.js"; class RulesController { // ==================== CRUD OPERATIONS ==================== // Get all system rules with advanced filtering static async getAllRules(req, res) { try { const { page = 1, limit = 50, rule_type, program_type, is_active, rule_name, effective_from, } = req.query; const result = await RulesModel.findAll(parseInt(page), parseInt(limit), { rule_type, program_type, is_active: is_active === "true" ? true : is_active === "false" ? false : undefined, rule_name, effective_from, }); return sendSuccess(res, "System rules retrieved successfully", result); } catch (error) { console.error("Get all rules error:", error); return sendError(res, "Failed to retrieve system rules", 500); } } // Get rule by ID static async getRuleById(req, res) { try { const { id } = req.params; const rule = await RulesModel.findById(parseInt(id)); if (!rule) { return sendError(res, "Rule not found", 404); } // Get history for this rule const history = await RulesModel.getRuleHistory(rule.rule_name); return sendSuccess(res, "Rule retrieved successfully", { rule, history, }); } catch (error) { console.error("Get rule error:", error); return sendError(res, "Failed to retrieve rule", 500); } } // Create a new rule static async createRule(req, res) { try { const { rule_name, rule_value, rule_type, program_type, effective_from, effective_to, description, } = req.body; // Validate required fields if (!rule_name || !rule_value || !rule_type || !effective_from) { return sendError( res, "Rule name, value, type, and effective from date are required", 400 ); } // Validate rule type const validRuleTypes = Object.values(RULE_TYPES); if (!validRuleTypes.includes(rule_type)) { return sendError( res, `Invalid rule type. Must be one of: ${validRuleTypes.join(", ")}`, 400 ); } // Validate program type if provided if (program_type && program_type !== "all") { const validProgramTypes = Object.values(PROGRAM_TYPES); if (!validProgramTypes.includes(program_type)) { return sendError( res, `Invalid program type. Must be one of: ${validProgramTypes.join( ", " )}`, 400 ); } } // Validate rule value if (!RulesModel.validateRuleValue(rule_type, rule_value)) { return sendError(res, `Invalid value for rule type: ${rule_type}`, 400); } // Validate dates if (effective_to && new Date(effective_from) >= new Date(effective_to)) { return sendError( res, "Effective from date must be before effective to date", 400 ); } const rule = await RulesModel.create({ rule_name, rule_value, rule_type, program_type: program_type || null, effective_from, effective_to: effective_to || null, description: description || null, }); return sendSuccess(res, "Rule created successfully", rule, 201); } catch (error) { console.error("Create rule error:", error); return sendError(res, error.message || "Failed to create rule", 400); } } // Update a rule (creates new version if active) static async updateRule(req, res) { try { const { id } = req.params; const updateData = req.body; // Check if rule exists const existingRule = await RulesModel.findById(parseInt(id)); if (!existingRule) { return sendError(res, "Rule not found", 404); } // Validate rule value if provided if (updateData.rule_value !== undefined) { const ruleType = updateData.rule_type || existingRule.rule_type; if (!RulesModel.validateRuleValue(ruleType, updateData.rule_value)) { return sendError( res, `Invalid value for rule type: ${ruleType}`, 400 ); } } // If rule is active and value is changing, create new version if ( existingRule.is_active && updateData.rule_value && updateData.rule_value !== existingRule.rule_value ) { const newRule = await RulesModel.create({ rule_name: existingRule.rule_name, rule_value: updateData.rule_value, rule_type: updateData.rule_type || existingRule.rule_type, program_type: updateData.program_type || existingRule.program_type, effective_from: new Date().toISOString().split("T")[0], effective_to: updateData.effective_to || null, description: updateData.description || existingRule.description, previous_version_id: existingRule.rule_id, }); // Deactivate the old rule await RulesModel.deactivate(existingRule.rule_id); return sendSuccess( res, "New rule version created and activated", newRule ); } // Otherwise, update normally const updatedRule = await RulesModel.update(parseInt(id), updateData); return sendSuccess(res, "Rule updated successfully", updatedRule); } catch (error) { console.error("Update rule error:", error); return sendError(res, error.message || "Failed to update rule", 400); } } // Delete a rule static async deleteRule(req, res) { try { const { id } = req.params; const existingRule = await RulesModel.findById(parseInt(id)); if (!existingRule) { return sendError(res, "Rule not found", 404); } if (existingRule.is_active) { return sendError( res, "Cannot delete active rule. Deactivate it first.", 400 ); } await RulesModel.delete(parseInt(id)); return sendSuccess(res, "Rule deleted successfully"); } catch (error) { console.error("Delete rule error:", error); return sendError(res, "Failed to delete rule", 500); } } // Activate a rule static async activateRule(req, res) { try { const { id } = req.params; const existingRule = await RulesModel.findById(parseInt(id)); if (!existingRule) { return sendError(res, "Rule not found", 404); } if (existingRule.is_active) { return sendError(res, "Rule is already active", 400); } const activatedRule = await RulesModel.activate(parseInt(id)); return sendSuccess(res, "Rule activated successfully", activatedRule); } catch (error) { console.error("Activate rule error:", error); return sendError(res, "Failed to activate rule", 500); } } // Deactivate a rule static async deactivateRule(req, res) { try { const { id } = req.params; const deactivatedRule = await RulesModel.deactivate(parseInt(id)); return sendSuccess(res, "Rule deactivated successfully", deactivatedRule); } catch (error) { console.error("Deactivate rule error:", error); return sendError(res, "Failed to deactivate rule", 500); } } // ==================== BUSINESS LOGIC OPERATIONS ==================== // Evaluate a rule static async evaluateRule(req, res) { try { const { rule_name, program_type = null, context = {} } = req.body; if (!rule_name) { return sendError(res, "Rule name is required", 400); } const result = await RulesModel.evaluate( rule_name, program_type, context ); return sendSuccess(res, "Rule evaluated successfully", result); } catch (error) { console.error("Evaluate rule error:", error); return sendError(res, error.message || "Failed to evaluate rule", 400); } } // Calculate load with factors static async calculateLoad(req, res) { try { const { lecture_hours, lab_hours = 0, tutorial_hours = 0, program_type = "regular", } = req.body; if (!lecture_hours && lecture_hours !== 0) { return sendError(res, "Lecture hours are required", 400); } const result = await RulesModel.calculateLoad( parseFloat(lecture_hours), parseFloat(lab_hours), parseFloat(tutorial_hours), program_type ); return sendSuccess(res, "Load calculated successfully", result); } catch (error) { console.error("Calculate load error:", error); return sendError(res, error.message || "Failed to calculate load", 400); } } // Validate rank load static async validateRankLoad(req, res) { try { const { rank, total_hours, program_type = "regular" } = req.body; if (!rank || total_hours === undefined) { return sendError(res, "Rank and total hours are required", 400); } const result = await RulesModel.validateRankLoad( rank, parseFloat(total_hours), program_type ); return sendSuccess(res, "Rank load validation completed", result); } catch (error) { console.error("Validate rank load error:", error); return sendError( res, error.message || "Failed to validate rank load", 400 ); } } // Calculate NRP payment static async calculateNRPPayment(req, res) { try { const { program_type, rate_category = "default", credit_hours, student_count = 0, } = req.body; if (!program_type || !credit_hours) { return sendError( res, "Program type and credit hours are required", 400 ); } const result = await RulesModel.calculateNRPPayment( program_type, rate_category, parseFloat(credit_hours), parseInt(student_count) ); return sendSuccess(res, "NRP payment calculated", result); } catch (error) { console.error("Calculate NRP payment error:", error); return sendError( res, error.message || "Failed to calculate NRP payment", 400 ); } } // Calculate overload payment static async calculateOverloadPayment(req, res) { try { const { overload_hours } = req.body; if (!overload_hours || overload_hours <= 0) { return sendError(res, "Valid overload hours are required", 400); } const result = await RulesModel.calculateOverloadPayment( parseFloat(overload_hours) ); return sendSuccess(res, "Overload payment calculated", result); } catch (error) { console.error("Calculate overload payment error:", error); return sendError( res, error.message || "Failed to calculate overload payment", 400 ); } } // Get correction rates static async getCorrectionRates(req, res) { try { const rates = await RulesModel.getCorrectionRates(); return sendSuccess(res, "Correction rates retrieved", rates); } catch (error) { console.error("Get correction rates error:", error); // Return default values if rules don't exist const defaultRates = { assignment: 10, exam: 15, tutorial: 150, }; return sendSuccess(res, "Correction rates retrieved (default)", defaultRates); } } // Apply summer distribution static async applySummerDistribution(req, res) { try { const { total_payment } = req.body; if (!total_payment || total_payment <= 0) { return sendError(res, "Valid total payment amount is required", 400); } const result = await RulesModel.applySummerDistribution( parseFloat(total_payment) ); return sendSuccess(res, "Summer distribution applied", result); } catch (error) { console.error("Apply summer distribution error:", error); // Return default distribution const defaultDistribution = { total: parseFloat(total_payment).toFixed(2), stage1: parseFloat((total_payment * 0.3).toFixed(2)), stage2: parseFloat((total_payment * 0.3).toFixed(2)), stage3: parseFloat((total_payment * 0.2).toFixed(2)), stage4: parseFloat((total_payment * 0.2).toFixed(2)), distribution: { stage1: 30.0, stage2: 30.0, stage3: 20.0, stage4: 20.0, }, }; return sendSuccess(res, "Summer distribution applied (default)", defaultDistribution); } } // ==================== UTILITY OPERATIONS ==================== // Get rule by name static async getRuleByName(req, res) { try { const { name } = req.params; const { program_type } = req.query; const rule = await RulesModel.findActiveRuleByName(name, program_type); if (!rule) { return sendError(res, `Rule '${name}' not found`, 404); } return sendSuccess(res, "Rule retrieved successfully", rule); } catch (error) { console.error("Get rule by name error:", error); return sendError(res, "Failed to retrieve rule", 500); } } // Get rules by type static async getRulesByType(req, res) { try { const { type } = req.params; const { program_type, active_only = "true" } = req.query; const validRuleTypes = Object.values(RULE_TYPES); if (!validRuleTypes.includes(type)) { return sendError( res, `Invalid rule type. Must be one of: ${validRuleTypes.join(", ")}`, 400 ); } const rules = await RulesModel.findByType( type, program_type, active_only === "true" ); return sendSuccess(res, `Rules of type ${type} retrieved`, rules); } catch (error) { console.error("Get rules by type error:", error); return sendError(res, "Failed to retrieve rules by type", 500); } } // Get rule history static async getRuleHistory(req, res) { try { const { name } = req.params; const history = await RulesModel.getRuleHistory(name); return sendSuccess(res, "Rule history retrieved", history); } catch (error) { console.error("Get rule history error:", error); return sendError(res, "Failed to retrieve rule history", 500); } } // Get rank load limits static async getRankLoadLimits(req, res) { try { const { rank } = req.params; const { program_type = "regular" } = req.query; const limits = await RulesModel.getRankLimits(rank, program_type); return sendSuccess(res, "Rank load limits retrieved", { rank, program_type, ...limits, }); } catch (error) { console.error("Get rank load limits error:", error); // Return null values if rules don't exist return sendSuccess(res, "Rank load limits retrieved", { rank, min: null, max: null, }); } } // Get all rank load limits static async getAllRankLoadLimits(req, res) { try { const { program_type = "regular" } = req.query; const limits = await RulesModel.getAllRankLoadLimits(program_type); return sendSuccess(res, "All rank load limits retrieved", limits); } catch (error) { console.error("Get all rank load limits error:", error); // Return empty object if error return sendSuccess(res, "All rank load limits retrieved", {}); } } // Get load factors static async getLoadFactors(req, res) { try { const { program_type = "regular" } = req.query; const factors = await RulesModel.getLoadFactors(program_type); return sendSuccess(res, "Load factors retrieved", factors); } catch (error) { console.error("Get load factors error:", error); // Return default factors const defaultFactors = { lab: 0.75, tutorial: 0.5, lecture: 1.0, module_distance: 1.0, }; return sendSuccess(res, "Load factors retrieved (default)", defaultFactors); } } // Get payment rates static async getPaymentRates(req, res) { try { const { program_type } = req.params; const { rate_category } = req.query; const rates = await RulesModel.getPaymentRate( program_type, rate_category ); return sendSuccess(res, "Payment rates retrieved", rates || {}); } catch (error) { console.error("Get payment rates error:", error); return sendSuccess(res, "Payment rates retrieved", {}); } } // Get summer distribution static async getSummerDistribution(req, res) { try { const distribution = await RulesModel.getSummerDistribution(); return sendSuccess(res, "Summer distribution retrieved", distribution); } catch (error) { console.error("Get summer distribution error:", error); // Return default distribution const defaultDistribution = { stage1: 30.0, stage2: 30.0, stage3: 20.0, stage4: 20.0, }; return sendSuccess(res, "Summer distribution retrieved (default)", defaultDistribution); } } // Bulk update rules static async bulkUpdateRules(req, res) { try { const { rules } = req.body; if (!rules || !Array.isArray(rules) || rules.length === 0) { return sendError(res, "Rules array is required", 400); } const results = await RulesModel.bulkUpdate(rules); return sendSuccess(res, "Rules updated successfully", results); } catch (error) { console.error("Bulk update rules error:", error); return sendError(res, "Failed to update rules", 500); } } // Validate workload static async validateWorkload(req, res) { try { const workloadData = req.body; if (!workloadData.staff_id) { return sendError(res, "Staff ID is required", 400); } const validation = await RulesModel.validateWorkload(workloadData); return sendSuccess(res, "Workload validation completed", validation); } catch (error) { console.error("Validate workload error:", error); return sendError( res, error.message || "Failed to validate workload", 400 ); } } // Get rules dashboard static async getRulesDashboard(req, res) { try { const dashboard = await RulesModel.getDashboardSummary(); return sendSuccess(res, "Rules dashboard retrieved", dashboard); } catch (error) { console.error("Get rules dashboard error:", error); return sendError(res, "Failed to get rules dashboard", 500); } } // Clear cache (admin only) static async clearCache(req, res) { try { RulesModel.clearCache(); return sendSuccess(res, "Rules cache cleared"); } catch (error) { console.error("Clear cache error:", error); return sendError(res, "Failed to clear cache", 500); } } // Get active rate tables static async getActiveRateTables(req, res) { try { const { program_type } = req.query; const rates = await RulesModel.getActiveRateTables(program_type); return sendSuccess(res, "Active rate tables retrieved", rates); } catch (error) { console.error("Get active rate tables error:", error); return sendError(res, "Failed to get rate tables", 500); } } // Get active tax rules static async getActiveTaxRules(req, res) { try { const { program_type } = req.query; const taxRules = await RulesModel.getActiveTaxRules(program_type); return sendSuccess(res, "Active tax rules retrieved", taxRules); } catch (error) { console.error("Get active tax rules error:", error); return sendError(res, "Failed to get tax rules", 500); } } } export default RulesController;// Calculate overload payment (NEW) static async calculateOverloadPayment(req, res) { try { const { staff_id, semester_id } = req.params; const { overload_hours, rate_per_hour } = req.body; if (!overload_hours || overload_hours <= 0) { return sendError(res, "Valid overload hours required", 400); } const calculation = await PaymentService.calculateOverloadPayment( staff_id, semester_id, overload_hours, rate_per_hour ); return sendSuccess(res, "Overload payment calculated successfully", { calculation, }); } catch (error) { console.error("Calculate overload payment error:", error); return sendError(res, "Failed to calculate overload payment", 500); } } // src/controllers/WorkloadNRPController.js - ENHANCED VERSION import WorkloadNRPModel from "../models/WorkloadNRPModel.js"; import WorkloadNRPService from "../services/WorkloadNRPService.js"; import StaffModel from "../models/StaffModel.js"; import { sendSuccess, sendError } from "../utils/response.js"; import { query } from "../config/database.js"; class WorkloadNRPController { // Create NRP workload static async createNRPWorkload(req, res) { try { console.log("Creating NRP workload for user:", req.user); const user_id = req.user.user_id; const user_role = req.user.role; // Handle different roles let staff_id; if (user_role === "admin") { if (!req.body.staff_id) { return sendError( res, "Please specify which staff member this workload is for.", 400 ); } staff_id = req.body.staff_id; } else if (user_role === "department_head" || user_role === "dean") { if (req.body.staff_id) { staff_id = req.body.staff_id; } else { const staff = await StaffModel.findByUserId(user_id); staff_id = staff?.staff_id; } } else if (user_role === "instructor") { const staff = await StaffModel.findByUserId(user_id); if (!staff) { return sendError( res, "We couldn't find your staff profile. Please contact the administrator to set up your profile first.", 404 ); } staff_id = staff.staff_id; } else { return sendError( res, "You don't have permission to create workloads. Please contact your department head if you believe this is an error.", 403 ); } // Validate staff_id if (!staff_id) { return sendError( res, "We couldn't identify which staff member this workload belongs to. Please try again or contact support.", 404 ); } // Check if staff exists const staff = await StaffModel.findById(staff_id); if (!staff) { return sendError( res, "The staff member you specified doesn't exist in our records. Please check the staff ID and try again.", 404 ); } const { semester_id, program_type, contract_number, academic_year, course_id, course_code, course_title, credit_hours = 0, lecture_credit_hours = 0, lab_credit_hours = 0, tutorial_credit_hours = 0, student_count = 0, teaching_hours = 0, module_hours = 0, lecture_sections = 0, lab_sections = 0, assignment_students = 0, exam_students = 0, rate_category = "default", contract_type = "teaching", academic_year_ec, contract_duration_from, contract_duration_to, is_overload = false, overload_hours = 0, } = req.body; // === VALIDATION WITH USER-FRIENDLY MESSAGES === // Validate required fields if (!semester_id) { return sendError( res, "Please select which semester this workload is for.", 400 ); } if (!program_type) { return sendError( res, "Please specify the program type (Extension, Weekend, Summer, or Distance).", 400 ); } // Validate program type const validProgramTypes = ["extension", "weekend", "summer", "distance"]; if (!validProgramTypes.includes(program_type.toLowerCase())) { return sendError( res, `"${program_type}" is not a valid program type. Please choose from: Extension, Weekend, Summer, or Distance.`, 400 ); } // Generate contract number if not provided let finalContractNumber = contract_number; if (!finalContractNumber) { try { finalContractNumber = await WorkloadNRPService.generateContractNumber( program_type, semester_id ); console.log(`Generated contract number: ${finalContractNumber}`); } catch (error) { console.error("Failed to generate contract number:", error); return sendError( res, "We couldn't generate a contract number. Please try again or enter one manually.", 500 ); } } // === DUPLICATE CHECKS === // 1. Check for duplicate contract number if (finalContractNumber) { try { const [existingContract] = await query( "SELECT nrp_id, status FROM workload_nrp WHERE contract_number = ? AND status != 'rejected'", [finalContractNumber] ); if (existingContract) { const statusMessage = existingContract.status === "draft" ? "This contract number is already being used in a draft workload. You can edit the existing draft instead." : "This contract number is already in use. Please use a different contract number."; return sendError( res, `Contract number "${finalContractNumber}" is already taken. ${statusMessage}`, 409 ); } } catch (dbError) { console.error("Database error during duplicate check:", dbError); // Continue with creation even if duplicate check fails console.log("Proceeding despite duplicate check error"); } } // 2. Check for similar active workloads (simplified version) try { const similarWorkloadQuery = ` SELECT nrp_id, status, course_code FROM workload_nrp WHERE staff_id = ? AND semester_id = ? AND program_type = ? AND status IN ('draft', 'submitted', 'approved') AND (course_code = ? OR ? IS NULL) `; const [similarWorkload] = await query(similarWorkloadQuery, [ staff_id, semester_id, program_type, course_code || null, course_code || null, ]); if (similarWorkload) { let message = "You already have "; if (similarWorkload.course_code) { message += `a ${program_type} workload for course ${similarWorkload.course_code} in this semester.`; } else { message += `a ${program_type} workload in this semester.`; } message += " You can edit the existing workload instead of creating a new one."; return sendError(res, message, 400); } } catch (similarError) { console.error("Error checking for similar workloads:", similarError); // Continue if this check fails } // 3. Check submission frequency (rate limiting) try { const [recentSubmissions] = await query( `SELECT COUNT(*) as count FROM workload_nrp WHERE staff_id = ? AND created_at > DATE_SUB(NOW(), INTERVAL 5 MINUTE)`, [staff_id] ); if (recentSubmissions.count > 3) { return sendError( res, "You're creating workloads too quickly. Please wait a few minutes before creating another one.", 429 ); } } catch (rateLimitError) { console.error("Rate limit check failed:", rateLimitError); // Continue if rate limiting fails } // === DATA PREPARATION === // Calculate total hours const total_hours_worked = teaching_hours + module_hours + overload_hours; // Helper function to clean numeric values const cleanNumericValue = (value) => { if (value === null || value === undefined || value === "") return 0; const strValue = String(value).replace(/,/g, "").trim(); const parts = strValue.split("."); if (parts.length > 2) { return parseFloat(parts[0] + "." + parts[1]) || 0; } return parseFloat(strValue) || 0; }; const nrpData = { staff_id, semester_id, program_type, contract_number: finalContractNumber, academic_year: academic_year || `${new Date().getFullYear()}`, course_id: course_id || null, course_code: course_code || "", course_title: course_title || "", credit_hours: cleanNumericValue(credit_hours), lecture_credit_hours: cleanNumericValue(lecture_credit_hours), lab_credit_hours: cleanNumericValue(lab_credit_hours), tutorial_credit_hours: cleanNumericValue(tutorial_credit_hours), student_count: parseInt(student_count) || 0, teaching_hours: cleanNumericValue(teaching_hours), module_hours: cleanNumericValue(module_hours), lecture_sections: parseInt(lecture_sections) || 0, lab_sections: parseInt(lab_sections) || 0, assignment_students: parseInt(assignment_students) || 0, exam_students: parseInt(exam_students) || 0, rate_category: rate_category || "default", contract_type, academic_year_ec, contract_duration_from, contract_duration_to, is_overload: is_overload ? 1 : 0, overload_hours: cleanNumericValue(overload_hours), total_hours_worked: cleanNumericValue(total_hours_worked), status: "draft", }; // === PAYMENT CALCULATION === try { // Check if calculatePayment exists in the service if (typeof WorkloadNRPService.calculatePayment === "function") { const paymentCalculation = await WorkloadNRPService.calculatePayment({ ...nrpData, academic_rank: staff.academic_rank, }); Object.assign(nrpData, paymentCalculation); } else { console.log( "calculatePayment not available, using default calculation" ); // Default payment calculation let defaultPayment = 0; const hours = nrpData.credit_hours || 3; switch (program_type.toLowerCase()) { case "extension": case "weekend": defaultPayment = hours * 500; break; case "summer": defaultPayment = nrpData.teaching_hours * 450; break; case "distance": defaultPayment = nrpData.module_hours * 520; break; default: defaultPayment = hours * 500; } nrpData.total_payment = defaultPayment; nrpData.teaching_payment = defaultPayment; } } catch (calcError) { console.error("Payment calculation error:", calcError); // Use safe default const defaultPayment = (nrpData.credit_hours || 3) * 500; nrpData.total_payment = defaultPayment; nrpData.teaching_payment = defaultPayment; } // === VALIDATION === try { // Check if validateWorkload exists if (typeof WorkloadNRPService.validateWorkload === "function") { const validation = await WorkloadNRPService.validateWorkload(nrpData); if (!validation.valid) { return sendError(res, "Please fix the following issues:", 400, { errors: validation.errors, warnings: validation.warnings, message: "There are some issues with your workload data. Please review and correct them.", }); } } } catch (validationError) { console.error("Validation error:", validationError); // Continue without validation if it fails } // === CREATE THE WORKLOAD === console.log("Creating NRP workload with data:", nrpData); const workload = await WorkloadNRPModel.createOrUpdate(nrpData); // === SUCCESS RESPONSE === return sendSuccess( res, "Workload created successfully! ✅", { nrp_id: workload.nrp_id, contract_number: workload.contract_number, status: workload.status, total_payment: workload.total_payment, next_steps: [ { action: "review", title: "Review your workload", description: "Check all the details are correct", }, { action: "edit", title: "Make changes if needed", description: "You can edit this workload while it's in draft status", }, { action: "submit", title: "Submit for approval", description: "Once everything is correct, submit it to your department head", }, ], helpful_tips: [ "Keep your contract number for future reference", "You can find this workload in your 'Draft' section", "Contact your department head if you have questions", ], }, 201 ); } catch (error) { console.error("Create NRP workload error:", error); // User-friendly error messages based on error type let userMessage = "We couldn't create your workload. "; let statusCode = 500; if (error.code === "ER_DUP_ENTRY") { userMessage += "This workload already exists in the system."; statusCode = 409; } else if (error.code === "ER_NO_REFERENCED_ROW_2") { userMessage += "Some information you entered doesn't exist in our records. Please check the semester, course, or staff details."; statusCode = 400; } else if (error.code === "ER_DATA_TOO_LONG") { userMessage += "Some information you entered is too long. Please shorten any text fields and try again."; statusCode = 400; } else if (error.message && error.message.includes("timeout")) { userMessage += "The request took too long. Please try again in a moment."; statusCode = 408; } else if (error.message && error.message.includes("connection")) { userMessage += "We're having trouble connecting to our database. Please try again in a few minutes."; statusCode = 503; } else { userMessage += "An unexpected error occurred. Our team has been notified."; } return sendError(res, userMessage, statusCode); } } // Get all NRP workloads static async getAllNRPWorkloads(req, res) { try { const { page = 1, limit = 20, semester_id, department_id, college_id, program_type, status, staff_id, date_from, date_to, search, } = req.query; const user_id = req.user.user_id; const user_role = req.user.role; // Build filters const filters = { page: parseInt(page), limit: parseInt(limit), }; // Add optional filters if (semester_id) filters.semester_id = parseInt(semester_id); if (department_id) filters.department_id = parseInt(department_id); if (college_id) filters.college_id = parseInt(college_id); if (program_type) filters.program_type = program_type; if (status) filters.status = status; if (staff_id) filters.staff_id = parseInt(staff_id); if (date_from) filters.date_from = date_from; if (date_to) filters.date_to = date_to; if (search) { filters.course_code = search; filters.contract_number = search; } // Role-based filtering if (user_role === "instructor") { // Instructors can only see their own workloads const staff = await StaffModel.findByUserId(user_id); if (staff) { filters.staff_id = staff.staff_id; } else { return sendSuccess(res, "No workloads found", { workloads: [], pagination: { total: 0 }, }); } } else if (user_role === "department_head") { // Department heads can see workloads in their department const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { filters.department_id = staff.department_id; } } else if (user_role === "dean") { // Deans can see workloads in their college const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { const [college] = await query( "SELECT college_id FROM departments WHERE department_id = ?", [staff.department_id] ); if (college) { filters.college_id = college.college_id; } } } const result = await WorkloadNRPModel.findAll(filters); return sendSuccess(res, "NRP workloads retrieved successfully", result); } catch (error) { console.error("Get all NRP workloads error:", error); return sendError( res, `Failed to retrieve NRP workloads: ${error.message}`, 500 ); } } // Get NRP workload by ID static async getNRPWorkloadById(req, res) { try { const { id } = req.params; const user_id = req.user.user_id; const user_role = req.user.role; console.log( `Getting NRP workload ${id} for user ${user_id} with role ${user_role}` ); const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } // Authorization check let authorized = false; if (user_role === "admin") { authorized = true; } else if (user_role === "instructor") { const staff = await StaffModel.findByUserId(user_id); authorized = staff?.staff_id === workload.staff_id; } else if (user_role === "department_head") { const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { // Get department of workload staff const [workloadDept] = await query( "SELECT department_id FROM staff_profiles WHERE staff_id = ?", [workload.staff_id] ); authorized = staff.department_id === workloadDept?.department_id; } } else if (user_role === "dean") { const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { // Get college of current user const [userCollege] = await query( `SELECT c.college_id FROM colleges c JOIN departments d ON c.college_id = d.college_id WHERE d.department_id = ?`, [staff.department_id] ); // Get department of workload staff const [workloadDept] = await query( "SELECT department_id FROM staff_profiles WHERE staff_id = ?", [workload.staff_id] ); if (workloadDept) { // Get college of workload staff const [workloadCollege] = await query( `SELECT c.college_id FROM colleges c JOIN departments d ON c.college_id = d.college_id WHERE d.department_id = ?`, [workloadDept.department_id] ); authorized = userCollege?.college_id === workloadCollege?.college_id; } } } else { // Other roles (registrar, finance, cde_director, hr_director, vpaf, etc.) authorized = true; } if (!authorized) { return sendError( res, "You are not authorized to view this workload", 403 ); } return sendSuccess(res, "NRP workload retrieved successfully", workload); } catch (error) { console.error("Get NRP workload error:", error); return sendError( res, `Failed to retrieve NRP workload: ${error.message}`, 500 ); } } // Update NRP workload static async updateNRPWorkload(req, res) { try { const { id } = req.params; const user_id = req.user.user_id; const user_role = req.user.role; const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } // Check authorization let canUpdate = false; if (user_role === "admin") { canUpdate = true; } else if (user_role === "instructor") { const staff = await StaffModel.findByUserId(user_id); canUpdate = staff?.staff_id === workload.staff_id && workload.status === "draft"; } else if (user_role === "department_head") { const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { const [workloadDept] = await query( "SELECT department_id FROM staff_profiles WHERE staff_id = ?", [workload.staff_id] ); canUpdate = staff.department_id === workloadDept?.department_id && (workload.status === "draft" || workload.status === "rejected"); } } if (!canUpdate) { return sendError( res, "You are not authorized to update this workload", 403 ); } const updateData = req.body; // Don't allow updating certain fields if already submitted if (workload.status !== "draft") { const restrictedFields = [ "staff_id", "semester_id", "program_type", "course_id", ]; restrictedFields.forEach((field) => { if (updateData[field] !== undefined) { delete updateData[field]; } }); } // If payment-related fields are updated, recalculate payment const paymentFields = [ "credit_hours", "lecture_credit_hours", "lab_credit_hours", "tutorial_credit_hours", "teaching_hours", "module_hours", // "tutorial_sessions", "assignment_students", "exam_students", "project_groups", "student_count", "rate_category", "is_overload", "overload_hours", ]; const needsRecalculation = paymentFields.some( (field) => updateData[field] !== undefined ); if (needsRecalculation) { // Get staff for rank-based calculation const staff = await StaffModel.findById(workload.staff_id); // Merge current data with updates const updatedWorkloadData = { ...workload, ...updateData }; // Calculate total hours updatedWorkloadData.total_hours_worked = WorkloadNRPService.calculateTotalHours(updatedWorkloadData); // Calculate payment const paymentCalculation = await WorkloadNRPService.calculatePayment({ ...updatedWorkloadData, academic_rank: staff?.academic_rank || "lecturer", }); // Add payment data to update Object.assign(updateData, paymentCalculation); } const updatedWorkload = await WorkloadNRPModel.update( parseInt(id), updateData ); return sendSuccess( res, "NRP workload updated successfully", updatedWorkload ); } catch (error) { console.error("Update NRP workload error:", error); return sendError( res, `Failed to update NRP workload: ${error.message}`, 500 ); } } // Submit for approval static async submitForApproval(req, res) { try { const { id } = req.params; const user_id = req.user.user_id; const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } // Check if user owns this workload const staff = await StaffModel.findByUserId(user_id); if (staff?.staff_id !== workload.staff_id) { return sendError(res, "You can only submit your own workloads", 403); } // Check if workload is in draft status if (workload.status !== "draft") { return sendError(res, "Only draft workloads can be submitted", 400); } // Validate workload before submission const validation = await WorkloadNRPService.validateWorkload(workload); if (!validation.valid) { return sendError( res, "Workload needs correction before submission", 400, { validation: validation, } ); } // Update status to submitted const updatedWorkload = await WorkloadNRPModel.update(parseInt(id), { status: "submitted", }); // Create approval workflow entry await query( `INSERT INTO approval_workflow (entity_type, entity_id, approver_role, status, created_at) VALUES ('workload_nrp', ?, ?, 'pending', NOW())`, [id, "department_head"] ); return sendSuccess( res, "NRP workload submitted for approval", updatedWorkload ); } catch (error) { console.error("Submit for approval error:", error); return sendError( res, `Failed to submit for approval: ${error.message}`, 500 ); } } // Get NRP statistics static async getNRPStatistics(req, res) { try { const { semester_id, department_id, program_type, date_from, date_to } = req.query; const user_id = req.user.user_id; const user_role = req.user.role; // Build filters const filters = {}; if (semester_id) filters.semester_id = semester_id; if (department_id) filters.department_id = department_id; if (program_type) filters.program_type = program_type; if (date_from) filters.date_from = date_from; if (date_to) filters.date_to = date_to; // Get dashboard statistics const stats = await WorkloadNRPService.getDashboardStats( user_role, user_id, filters ); return sendSuccess(res, "NRP statistics retrieved", stats); } catch (error) { console.error("Get NRP statistics error:", error); return sendError( res, `Failed to get NRP statistics: ${error.message}`, 500 ); } } // Get my NRP workloads (instructor only) static async getMyNRPWorkloads(req, res) { try { const user_id = req.user.user_id; const staff = await StaffModel.findByUserId(user_id); if (!staff) { return sendSuccess(res, "No workloads found", { workloads: [] }); } const { semester_id, program_type, status } = req.query; const filters = { staff_id: staff.staff_id, }; if (semester_id) filters.semester_id = parseInt(semester_id); if (program_type) filters.program_type = program_type; if (status) filters.status = status; const result = await WorkloadNRPModel.findAll(1, 100, filters); return sendSuccess(res, "My NRP workloads retrieved", result.workloads); } catch (error) { console.error("Get my NRP workloads error:", error); return sendError(res, `Failed to get workloads: ${error.message}`, 500); } } // Calculate payment for a workload static async calculatePayment(req, res) { try { const { id } = req.params; const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } // Get staff for rank-based calculation const staff = await StaffModel.findById(workload.staff_id); // Calculate payment const paymentCalculation = await WorkloadNRPService.calculatePayment({ ...workload, academic_rank: staff?.academic_rank || "lecturer", }); return sendSuccess(res, "Payment calculated successfully", { workload_id: id, ...paymentCalculation, }); } catch (error) { console.error("Calculate payment error:", error); return sendError( res, `Failed to calculate payment: ${error.message}`, 500 ); } } // Get approval workflow for NRP static async getApprovalWorkflow(req, res) { try { const { id } = req.params; const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } const approvals = await query( `SELECT aw.*, u.username as approver_username, u.email as approver_email, sp.first_name as approver_first_name, sp.last_name as approver_last_name FROM approval_workflow aw LEFT JOIN users u ON aw.approver_id = u.user_id LEFT JOIN staff_profiles sp ON u.user_id = sp.user_id WHERE aw.entity_type = 'workload_nrp' AND aw.entity_id = ? ORDER BY aw.created_at`, [id] ); return sendSuccess(res, "Approval workflow retrieved", { workload_id: id, current_status: workload.status, approvals: approvals || [], }); } catch (error) { console.error("Get approval workflow error:", error); return sendError( res, `Failed to get approval workflow: ${error.message}`, 500 ); } } // Approve workload step static async approveWorkloadStep(req, res) { try { const { id } = req.params; const { comments = "" } = req.body; const approver_id = req.user.user_id; const approver_role = req.user.role; const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } // Check if user can approve this step const [pendingApproval] = await query( `SELECT * FROM approval_workflow WHERE entity_type = 'workload_nrp' AND entity_id = ? AND approver_role = ? AND status = 'pending' ORDER BY created_at LIMIT 1`, [id, approver_role] ); if (!pendingApproval) { return sendError(res, "No pending approval found for your role", 400); } // Update approval await query( `UPDATE approval_workflow SET status = 'approved', approver_id = ?, comments = ?, updated_at = NOW() WHERE approval_id = ?`, [approver_id, comments, pendingApproval.approval_id] ); // Determine next status based on approver role const statusMap = { department_head: "dh_approved", dean: "dean_approved", cde_director: "cde_approved", hr_director: "hr_approved", vpaf: "vpaf_approved", finance: "finance_approved", }; const newStatus = statusMap[approver_role]; if (newStatus) { await WorkloadNRPModel.update(parseInt(id), { status: newStatus }); } // Create next approval step if needed const nextRoleMap = { department_head: "dean", dean: "cde_director", cde_director: "hr_director", hr_director: "vpaf", vpaf: "finance", finance: null, }; const nextRole = nextRoleMap[approver_role]; if (nextRole) { await query( `INSERT INTO approval_workflow (entity_type, entity_id, approver_role, status, created_at) VALUES ('workload_nrp', ?, ?, 'pending', NOW())`, [id, nextRole] ); } const updatedWorkload = await WorkloadNRPModel.findById(parseInt(id)); return sendSuccess( res, "Workload approved successfully", updatedWorkload ); } catch (error) { console.error("Approve workload step error:", error); return sendError( res, `Failed to approve workload: ${error.message}`, 500 ); } } // Reject workload static async rejectWorkload(req, res) { try { const { id } = req.params; const { comments } = req.body; const approver_id = req.user.user_id; const approver_role = req.user.role; if (!comments) { return sendError(res, "Rejection comments are required", 400); } const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } // Check if user can reject (same roles that can approve) const allowedRoles = [ "department_head", "dean", "cde_director", "hr_director", "vpaf", "finance", ]; if (!allowedRoles.includes(approver_role)) { return sendError( res, "You are not authorized to reject workloads", 403 ); } // Update any pending approvals await query( `UPDATE approval_workflow SET status = 'rejected', approver_id = ?, comments = ?, updated_at = NOW() WHERE entity_type = 'workload_nrp' AND entity_id = ? AND status = 'pending'`, [approver_id, comments, id] ); // Update workload status const updatedWorkload = await WorkloadNRPModel.update(parseInt(id), { status: "rejected", }); return sendSuccess( res, "Workload rejected successfully", updatedWorkload ); } catch (error) { console.error("Reject workload error:", error); return sendError(res, `Failed to reject workload: ${error.message}`, 500); } } // Return workload for correction static async returnForCorrection(req, res) { try { const { id } = req.params; const { comments } = req.body; const approver_id = req.user.user_id; const approver_role = req.user.role; if (!comments) { return sendError(res, "Return comments are required", 400); } const workload = await WorkloadNRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "NRP workload not found", 404); } // Check if user can return (same roles that can approve) const allowedRoles = [ "department_head", "dean", "cde_director", "hr_director", "vpaf", "finance", ]; if (!allowedRoles.includes(approver_role)) { return sendError( res, "You are not authorized to return workloads", 403 ); } // Update the current pending approval await query( `UPDATE approval_workflow SET status = 'returned', approver_id = ?, comments = ?, updated_at = NOW() WHERE entity_type = 'workload_nrp' AND entity_id = ? AND status = 'pending' ORDER BY created_at DESC LIMIT 1`, [approver_id, comments, id] ); // Update workload status back to draft const updatedWorkload = await WorkloadNRPModel.update(parseInt(id), { status: "draft", }); return sendSuccess( res, "Workload returned for correction", updatedWorkload ); } catch (error) { console.error("Return for correction error:", error); return sendError(res, `Failed to return workload: ${error.message}`, 500); } } // Get pending approvals for current user static async getMyPendingApprovals(req, res) { try { const user_id = req.user.user_id; const user_role = req.user.role; const pendingApprovals = await query( `SELECT aw.*, wn.nrp_id, wn.program_type, wn.course_code, wn.course_title, wn.total_payment, wn.status as workload_status, sp.first_name as staff_first_name, sp.last_name as staff_last_name, sp.employee_id, d.department_name, s.semester_code, s.semester_name FROM approval_workflow aw JOIN workload_nrp wn ON aw.entity_id = wn.nrp_id JOIN staff_profiles sp ON wn.staff_id = sp.staff_id JOIN departments d ON sp.department_id = d.department_id JOIN semesters s ON wn.semester_id = s.semester_id WHERE aw.approver_role = ? AND aw.status = 'pending' ORDER BY aw.created_at`, [user_role] ); return sendSuccess(res, "Pending approvals retrieved", pendingApprovals); } catch (error) { console.error("Get pending approvals error:", error); return sendError( res, `Failed to get pending approvals: ${error.message}`, 500 ); } } } export default WorkloadNRPController; import WorkloadReportService from "../services/WorkloadReportService.js"; import { sendSuccess, sendError } from "../utils/response.js"; import StaffModel from "../models/StaffModel.js"; import { query } from "../config/database.js"; // ADD THIS IMPORT class WorkloadReportController { // Generate comprehensive workload report static async generateReport(req, res) { try { const user_id = req.user.user_id; const user_role = req.user.role; const { semester_id, department_id, college_id, staff_id, program_type, status, date_from, date_to, report_type = "comprehensive", } = req.query; // Build filters based on user role const filters = { semester_id: semester_id ? parseInt(semester_id) : null, program_type, status, date_from, date_to, report_type, }; // Role-based filtering if (user_role === "instructor") { // Instructors can only see their own data const staff = await StaffModel.findByUserId(user_id); if (staff) { filters.staff_id = staff.staff_id; } else { return sendError(res, "Staff profile not found", 404); } } else if (user_role === "department_head") { // Department heads can see their department data const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { filters.department_id = staff.department_id; } } else if (user_role === "dean") { // Deans can see their college data const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { // Get college from department const [college] = await query( `SELECT c.college_id FROM colleges c JOIN departments d ON c.college_id = d.college_id WHERE d.department_id = ?`, [staff.department_id] ); if (college) { filters.college_id = college.college_id; } } } else { // Admin and other roles can specify filters if (department_id) filters.department_id = parseInt(department_id); if (college_id) filters.college_id = parseInt(college_id); if (staff_id) filters.staff_id = parseInt(staff_id); } console.log( `Generating report for user ${user_id} (${user_role}) with filters:`, filters ); // Generate report const report = await WorkloadReportService.generateComprehensiveReport( filters ); // Add user context to report report.user_context = { user_id, user_role, generated_by: `${req.user.username} (${user_role})`, generated_at: new Date().toISOString(), }; return sendSuccess(res, "Workload report generated successfully", report); } catch (error) { console.error("Generate report error:", error); return sendError(res, `Failed to generate report: ${error.message}`, 500); } } // Export report in specific format static async exportReport(req, res) { try { const { format = "json" } = req.query; const reportData = req.body; // Assume report data is passed in body if (!reportData) { return sendError(res, "Report data is required", 400); } const validFormats = ["pdf", "excel", "csv", "json"]; if (!validFormats.includes(format.toLowerCase())) { return sendError( res, `Invalid format. Supported formats: ${validFormats.join(", ")}`, 400 ); } const exported = await WorkloadReportService.exportReport( reportData, format ); // Set appropriate headers for download res.setHeader("Content-Type", this.getContentType(format)); res.setHeader( "Content-Disposition", `attachment; filename="${exported.filename}"` ); if (format === "json") { return res.json(exported.data); } else { return res.send(exported.data); } } catch (error) { console.error("Export report error:", error); return sendError(res, `Failed to export report: ${error.message}`, 500); } } // Get available semesters for filtering static async getAvailableSemesters(req, res) { try { const semesters = await WorkloadReportService.getAvailableSemesters(); return sendSuccess(res, "Available semesters retrieved", semesters); } catch (error) { console.error("Get semesters error:", error); return sendError(res, "Failed to retrieve semesters", 500); } } // Get department statistics static async getDepartmentStats(req, res) { try { const user_id = req.user.user_id; const user_role = req.user.role; const { departmentId } = req.params; // Check permissions if (user_role === "department_head") { const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id !== parseInt(departmentId)) { return sendError( res, "You can only view your own department statistics", 403 ); } } else if (user_role === "dean") { // Deans can view departments in their college const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { const [college] = await query( `SELECT c.college_id FROM colleges c JOIN departments d ON c.college_id = d.college_id WHERE d.department_id = ?`, [staff.department_id] ); if (college) { // Check if requested department is in same college const [deptCollege] = await query( `SELECT college_id FROM departments WHERE department_id = ?`, [departmentId] ); if (!deptCollege || deptCollege.college_id !== college.college_id) { return sendError( res, "You can only view departments in your college", 403 ); } } } } const stats = await WorkloadReportService.getDepartmentStatistics( parseInt(departmentId) ); return sendSuccess(res, "Department statistics retrieved", stats); } catch (error) { console.error("Get department stats error:", error); return sendError(res, "Failed to retrieve department statistics", 500); } } // Get staff performance report static async getStaffPerformance(req, res) { try { const user_id = req.user.user_id; const user_role = req.user.role; const { staffId } = req.params; const { semester_id } = req.query; // ADDED: get semester_id from query // Check permissions if (user_role === "instructor") { const staff = await StaffModel.findByUserId(user_id); if (!staff || staff.staff_id !== parseInt(staffId)) { return sendError(res, "You can only view your own performance", 403); } } else if (user_role === "department_head") { const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { // Check if requested staff is in same department const [targetStaff] = await query( `SELECT department_id FROM staff_profiles WHERE staff_id = ?`, [staffId] ); if ( !targetStaff || targetStaff.department_id !== staff.department_id ) { return sendError( res, "You can only view staff in your department", 403 ); } } } const performance = await WorkloadReportService.getStaffPerformanceReport( parseInt(staffId), semester_id ? parseInt(semester_id) : null ); if (!performance) { return sendError(res, "Staff performance data not found", 404); } return sendSuccess(res, "Staff performance retrieved", performance); } catch (error) { console.error("Get staff performance error:", error); return sendError(res, "Failed to retrieve staff performance", 500); } } // Get workload summary dashboard static async getDashboardSummary(req, res) { try { const user_id = req.user.user_id; const user_role = req.user.role; // Get current semester const [currentSemester] = await query( "SELECT semester_id FROM semesters WHERE is_active = TRUE LIMIT 1" ); if (!currentSemester) { return sendError(res, "No active semester found", 404); } const filters = { semester_id: currentSemester.semester_id, }; // Apply role-based filtering if (user_role === "instructor") { const staff = await StaffModel.findByUserId(user_id); if (staff) { filters.staff_id = staff.staff_id; } } else if (user_role === "department_head") { const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { filters.department_id = staff.department_id; } } else if (user_role === "dean") { const staff = await StaffModel.findByUserId(user_id); if (staff && staff.department_id) { const [college] = await query( `SELECT c.college_id FROM colleges c JOIN departments d ON c.college_id = d.college_id WHERE d.department_id = ?`, [staff.department_id] ); if (college) { filters.college_id = college.college_id; } } } // Generate dashboard summary const report = await WorkloadReportService.generateComprehensiveReport( filters ); // Extract key metrics for dashboard const dashboard = { overview: { total_workloads: report.data.rp_workloads.length + report.data.nrp_workloads.length, total_hours: report.statistics.overall.total_hours, total_payment: report.statistics.overall.total_payment, active_staff: report.statistics.overall.staff_count, departments: report.statistics.overall.department_count, }, rp_summary: { total_workloads: report.data.rp_workloads.length, average_hours: report.statistics.rp.average_load, total_payment: report.statistics.rp.total_over_payment, by_status: report.statistics.rp.by_status, }, nrp_summary: { total_workloads: report.data.nrp_workloads.length, total_payment: report.statistics.nrp.total_payment, by_program: report.statistics.nrp.by_program, }, recent_activity: { last_week_workloads: await this.getRecentActivity( filters.semester_id, 7 ), pending_approvals: await this.getPendingApprovals(user_role, user_id), }, trends: report.trends, }; return sendSuccess(res, "Dashboard summary retrieved", dashboard); } catch (error) { console.error("Get dashboard summary error:", error); return sendError(res, "Failed to retrieve dashboard summary", 500); } } // Helper methods static getContentType(format) { const contentTypes = { pdf: "application/pdf", excel: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", csv: "text/csv", json: "application/json", }; return contentTypes[format] || "application/octet-stream"; } static async getRecentActivity(semester_id, days = 7) { try { const recentWorkloads = await query( ` SELECT 'RP' as type, workload_id as id, course_code, total_load as hours, status, created_at, staff_id FROM workload_rp WHERE semester_id = ? AND created_at >= DATE_SUB(NOW(), INTERVAL ? DAY) UNION ALL SELECT 'NRP' as type, nrp_id as id, course_code, total_hours_worked as hours, status, created_at, staff_id FROM workload_nrp WHERE semester_id = ? AND created_at >= DATE_SUB(NOW(), INTERVAL ? DAY) ORDER BY created_at DESC LIMIT 10 `, [semester_id, days, semester_id, days] ); return recentWorkloads; } catch (error) { console.error("Get recent activity error:", error); return []; } } static async getPendingApprovals(user_role, user_id) { try { let pendingQuery = ""; const params = []; if (user_role === "department_head") { // Get department head's department const [dept] = await query( `SELECT d.department_id FROM departments d JOIN staff_profiles sp ON d.head_user_id = sp.user_id WHERE sp.user_id = ?`, [user_id] ); if (dept) { pendingQuery = ` SELECT COUNT(*) as count FROM ( SELECT wr.workload_id, wr.status, wr.staff_id FROM workload_rp wr JOIN staff_profiles sp ON wr.staff_id = sp.staff_id WHERE sp.department_id = ? AND wr.status = 'submitted' UNION ALL SELECT wn.nrp_id, wn.status, wn.staff_id FROM workload_nrp wn JOIN staff_profiles sp ON wn.staff_id = sp.staff_id WHERE sp.department_id = ? AND wn.status = 'submitted' ) as pending `; params.push(dept.department_id, dept.department_id); } } else if (user_role === "dean") { // Get dean's college const [college] = await query( `SELECT c.college_id FROM colleges c WHERE c.dean_user_id = ?`, [user_id] ); if (college) { pendingQuery = ` SELECT COUNT(*) as count FROM ( SELECT wr.workload_id, wr.status, wr.staff_id FROM workload_rp wr JOIN staff_profiles sp ON wr.staff_id = sp.staff_id JOIN departments d ON sp.department_id = d.department_id WHERE d.college_id = ? AND wr.status = 'dh_approved' UNION ALL SELECT wn.nrp_id, wn.status, wn.staff_id FROM workload_nrp wn JOIN staff_profiles sp ON wn.staff_id = sp.staff_id JOIN departments d ON sp.department_id = d.department_id WHERE d.college_id = ? AND wn.status = 'dh_approved' ) as pending `; params.push(college.college_id, college.college_id); } } if (pendingQuery) { const [result] = await query(pendingQuery, params); return result?.count || 0; } return 0; } catch (error) { console.error("Get pending approvals error:", error); return 0; } } } export default WorkloadReportController;// export default WorkloadRPController; import { query } from "../config/database.js"; import { sendSuccess, sendError } from "../utils/response.js"; // Dynamic imports to avoid circular dependencies let WorkloadRPModel, WorkloadService; async function getWorkloadRPModel() { if (!WorkloadRPModel) { WorkloadRPModel = (await import("../models/WorkloadRPModel.js")).default; } return WorkloadRPModel; } async function getWorkloadService() { if (!WorkloadService) { WorkloadService = (await import("../services/WorkloadService.js")).default; } return WorkloadService; } class WorkloadRPController { // Create or update workload static async createOrUpdateWorkload(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const staffId = req.user.role === "instructor" ? await WorkloadRPController.getStaffIdFromUserId(req.user.user_id) : req.body.staff_id; if (!staffId) { return sendError(res, "Staff ID is required", 400); } // Instructors can only create/update their own workloads if (req.user.role === "instructor") { const userStaffId = await WorkloadRPController.getStaffIdFromUserId( req.user.user_id ); if (parseInt(staffId) !== userStaffId) { return sendError(res, "You can only manage your own workload", 403); } } const { semester_id, course_code, course_credit_hours = 0, lecture_credit_hours = 0, tutorial_credit_hours = 0, lab_credit_hours = 0, student_department, academic_year, number_of_sections = 1, each_section_course_load = 0, variety_of_course_load = 0, research_load = 0, community_service_load = 0, elip_load = 0, hdp_load = 0, course_chair_load = 0, section_advisor_load = 0, advising_load = 0, position_load = 0, total_load, over_payment_birr = 0, status = "draft", } = req.body; // Validate required fields if (!semester_id) { return sendError(res, "Semester ID is required", 400); } if (!course_code) { return sendError(res, "Course code is required", 400); } if (number_of_sections <= 0) { return sendError(res, "Number of sections must be greater than 0", 400); } // Validate hours are not negative const hours = [ course_credit_hours, lecture_credit_hours, tutorial_credit_hours, lab_credit_hours, each_section_course_load, variety_of_course_load, research_load, community_service_load, elip_load, hdp_load, course_chair_load, section_advisor_load, advising_load, position_load, ]; if (hours.some((h) => h < 0)) { return sendError(res, "Load values cannot be negative", 400); } // Calculate total load if not provided let calculatedTotalLoad = total_load; if (!calculatedTotalLoad) { const courseLoad = each_section_course_load * number_of_sections; calculatedTotalLoad = courseLoad + variety_of_course_load + research_load + community_service_load + elip_load + hdp_load + course_chair_load + section_advisor_load + advising_load + position_load; } // Create or update workload const workload = await WorkloadRPModel.createOrUpdate({ staff_id: parseInt(staffId), semester_id: parseInt(semester_id), course_code, course_credit_hours: parseFloat(course_credit_hours), lecture_credit_hours: parseFloat(lecture_credit_hours), tutorial_credit_hours: parseFloat(tutorial_credit_hours), lab_credit_hours: parseFloat(lab_credit_hours), student_department, academic_year, number_of_sections: parseInt(number_of_sections), each_section_course_load: parseFloat(each_section_course_load), variety_of_course_load: parseFloat(variety_of_course_load), research_load: parseFloat(research_load), community_service_load: parseFloat(community_service_load), elip_load: parseFloat(elip_load), hdp_load: parseFloat(hdp_load), course_chair_load: parseFloat(course_chair_load), section_advisor_load: parseFloat(section_advisor_load), advising_load: parseFloat(advising_load), position_load: parseFloat(position_load), total_load: parseFloat(calculatedTotalLoad), over_payment_birr: parseFloat(over_payment_birr), status, }); return sendSuccess( res, "Workload saved successfully", workload, workload.workload_id ? 200 : 201 ); } catch (error) { console.error("Create/update workload error:", error); return sendError(res, error.message || "Failed to save workload", 500); } } // Get workload by ID static async getWorkloadById(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { id } = req.params; const workload = await WorkloadRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "Workload not found", 404); } // Check permissions if (!WorkloadRPController.canViewWorkload(req.user, workload)) { return sendError(res, "Access denied", 403); } // Format response with column groups const formattedWorkload = WorkloadRPController.formatWorkloadResponse(workload); return sendSuccess( res, "Workload retrieved successfully", formattedWorkload ); } catch (error) { console.error("Get workload error:", error); return sendError(res, "Failed to retrieve workload", 500); } } // Get all workloads with filters (CORRECTED SINGLE METHOD) static async getAllWorkloads(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { page = 1, limit = 20, staff_id, semester_id, department_id, college_id, status, course_code, academic_rank, } = req.query; // Check permissions based on role let filters = {}; if (req.user.role === "instructor") { // Instructors can only see their own workloads const staffId = await WorkloadRPController.getStaffIdFromUserId( req.user.user_id ); if (staffId) { filters.staff_id = staffId; } else { return sendError(res, "Staff profile not found", 404); } } else if (req.user.role === "department_head") { // Department heads can see workloads in their department const departmentId = await WorkloadRPController.getUserDepartmentId( req.user.user_id ); if (departmentId) { filters.department_id = departmentId; } } else if (req.user.role === "dean") { // Deans can see workloads in their college const collegeId = await WorkloadRPController.getUserCollegeId( req.user.user_id ); if (collegeId) { filters.college_id = collegeId; } } // Apply query filters if (staff_id) filters.staff_id = parseInt(staff_id); if (semester_id) filters.semester_id = parseInt(semester_id); if (department_id) filters.department_id = parseInt(department_id); if (college_id) filters.college_id = parseInt(college_id); if (status) filters.status = status; if (course_code) filters.course_code = course_code; if (academic_rank) filters.academic_rank = academic_rank; const result = await WorkloadRPModel.findAll( parseInt(page), parseInt(limit), filters ); // Format workloads if (result.workloads && Array.isArray(result.workloads)) { result.workloads = result.workloads.map((workload) => WorkloadRPController.formatWorkloadResponse(workload) ); } return sendSuccess(res, "Workloads retrieved successfully", result); } catch (error) { console.error("Get all workloads error:", error); return sendError(res, "Failed to retrieve workloads", 500); } } // Get my workload (for instructors) static async getMyWorkload(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const staffId = await WorkloadRPController.getStaffIdFromUserId( req.user.user_id ); if (!staffId) { return sendError(res, "Staff profile not found", 404); } const { semester_id } = req.query; let workload; if (semester_id) { workload = await WorkloadRPModel.findByStaffAndSemester( staffId, parseInt(semester_id) ); } else { // Get latest workload const result = await WorkloadRPModel.findAll(1, 1, { staff_id: staffId, }); workload = result.workloads[0] || null; } if (!workload) { return sendError(res, "No workload found", 404); } const fullWorkload = await WorkloadRPModel.findById(workload.workload_id); const formattedWorkload = WorkloadRPController.formatWorkloadResponse(fullWorkload); return sendSuccess(res, "Workload retrieved", formattedWorkload); } catch (error) { console.error("Get my workload error:", error); return sendError(res, "Failed to retrieve workload", 500); } } // Get workload dashboard static async getWorkloadDashboard(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const staffId = await WorkloadRPController.getStaffIdFromUserId( req.user.user_id ); const { semester_id } = req.query; if (!semester_id) { return sendError(res, "Semester ID is required", 400); } const workload = await WorkloadRPModel.findByStaffAndSemester( staffId, parseInt(semester_id) ); if (!workload) { return sendSuccess(res, "No workload for this semester", { semester_id, has_workload: false, dashboard_data: null, }); } const fullWorkload = await WorkloadRPModel.findById(workload.workload_id); // Calculate dashboard metrics const dashboardData = { total_load: fullWorkload.total_load, course_load: fullWorkload.each_section_course_load * fullWorkload.number_of_sections, research_community_load: fullWorkload.research_load + fullWorkload.community_service_load, admin_load: fullWorkload.elip_load + fullWorkload.hdp_load + fullWorkload.course_chair_load + fullWorkload.section_advisor_load + fullWorkload.advising_load + fullWorkload.position_load, over_payment: fullWorkload.over_payment_birr, status: fullWorkload.status, approval_progress: await WorkloadRPController.calculateApprovalProgress( fullWorkload.workload_id ), }; return sendSuccess(res, "Dashboard data retrieved", { workload: WorkloadRPController.formatWorkloadResponse(fullWorkload), dashboard_data: dashboardData, }); } catch (error) { console.error("Get dashboard error:", error); return sendError(res, "Failed to retrieve dashboard data", 500); } } // Calculate workload from sections (auto-calculate) static async calculateFromSections(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const staffId = req.user.role === "instructor" ? await WorkloadRPController.getStaffIdFromUserId(req.user.user_id) : req.body.staff_id; if (!staffId) { return sendError(res, "Staff ID is required", 400); } const { semester_id } = req.body; if (!semester_id) { return sendError(res, "Semester ID is required", 400); } // Check permissions if (req.user.role === "instructor") { const userStaffId = await WorkloadRPController.getStaffIdFromUserId( req.user.user_id ); if (parseInt(staffId) !== userStaffId) { return sendError( res, "You can only calculate your own workload", 403 ); } } const calculated = await WorkloadRPModel.calculateFromSections( parseInt(staffId), parseInt(semester_id) ); return sendSuccess(res, "Workload calculated from sections", calculated); } catch (error) { console.error("Calculate from sections error:", error); return sendError( res, error.message || "Failed to calculate workload", 500 ); } } // Get workload statistics static async getWorkloadStatistics(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); let { semester_id, department_id } = req.query; // Check permissions for department heads and deans if (req.user.role === "department_head") { const userDeptId = await WorkloadRPController.getUserDepartmentId( req.user.user_id ); if (userDeptId) { department_id = userDeptId; } } const stats = await WorkloadRPModel.getStatistics( semester_id ? parseInt(semester_id) : null, department_id ? parseInt(department_id) : null ); return sendSuccess(res, "Workload statistics retrieved", stats); } catch (error) { console.error("Get statistics error:", error); return sendError(res, "Failed to retrieve statistics", 500); } } // Get department workload summary static async getDepartmentWorkloadSummary(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { departmentId } = req.params; const { semester_id } = req.query; if (!semester_id) { return sendError(res, "Semester ID is required", 400); } // Check permissions if (req.user.role === "department_head") { const userDeptId = await WorkloadRPController.getUserDepartmentId( req.user.user_id ); if (parseInt(departmentId) !== userDeptId) { return sendError(res, "You can only view your own department", 403); } } const summary = await WorkloadRPModel.getDepartmentSummary( parseInt(departmentId), parseInt(semester_id) ); return sendSuccess(res, "Department workload summary", { department_id: departmentId, semester_id, summary, }); } catch (error) { console.error("Get department summary error:", error); return sendError(res, "Failed to retrieve department summary", 500); } } // Submit workload for approval static async submitForApproval(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const WorkloadService = await getWorkloadService(); const { id } = req.params; // Check if workload exists const workload = await WorkloadRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "Workload not found", 404); } // Check permissions if (!WorkloadRPController.canSubmitWorkload(req.user, workload)) { return sendError(res, "You cannot submit this workload", 403); } // Validate before submission const validation = await WorkloadService.validateWorkloadCompliance( workload ); if (validation.status !== "compliant") { return sendError( res, "Workload needs correction before submission", 400, { validation, } ); } // Submit for approval const submittedWorkload = await WorkloadRPModel.submitForApproval( parseInt(id), req.user.user_id ); return sendSuccess( res, "Workload submitted for approval", submittedWorkload ); } catch (error) { console.error("Submit workload error:", error); return sendError(res, error.message || "Failed to submit workload", 400); } } // Get approval workflow static async getApprovalWorkflow(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { id } = req.params; const workload = await WorkloadRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "Workload not found", 404); } if (!WorkloadRPController.canViewWorkload(req.user, workload)) { return sendError(res, "Access denied", 403); } const workflow = await WorkloadRPModel.getApprovalWorkflow(parseInt(id)); return sendSuccess(res, "Approval workflow retrieved", workflow); } catch (error) { console.error("Get approval workflow error:", error); return sendError(res, "Failed to retrieve approval workflow", 500); } } // Approve step static async approveStep(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { approvalId } = req.params; const { comments = "" } = req.body; const [approval] = await query( "SELECT * FROM approval_workflow WHERE approval_id = ?", [approvalId] ); if (!approval) { return sendError(res, "Approval not found", 404); } if (!WorkloadRPController.canApproveStep(req.user, approval)) { return sendError(res, "You cannot approve this step", 403); } const approved = await WorkloadRPModel.approveStep( parseInt(approvalId), req.user.user_id, comments ); return sendSuccess(res, "Approval completed", approved); } catch (error) { console.error("Approve step error:", error); return sendError(res, error.message || "Failed to approve step", 400); } } // Reject workload static async rejectWorkload(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { id } = req.params; const { comments } = req.body; if (!comments) { return sendError(res, "Rejection comments required", 400); } const workload = await WorkloadRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "Workload not found", 404); } if (!WorkloadRPController.canRejectWorkload(req.user, workload)) { return sendError(res, "You cannot reject this workload", 403); } const rejectedWorkload = await WorkloadRPModel.rejectWorkload( parseInt(id), req.user.user_id, comments ); return sendSuccess(res, "Workload rejected", rejectedWorkload); } catch (error) { console.error("Reject workload error:", error); return sendError(res, error.message || "Failed to reject workload", 400); } } // Return workload for correction static async returnForCorrection(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { id } = req.params; const { comments } = req.body; if (!comments) { return sendError(res, "Return comments required", 400); } const workload = await WorkloadRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "Workload not found", 404); } if (!WorkloadRPController.canReturnWorkload(req.user, workload)) { return sendError(res, "You cannot return this workload", 403); } const returnedWorkload = await WorkloadRPModel.returnForCorrection( parseInt(id), req.user.user_id, comments ); return sendSuccess( res, "Workload returned for correction", returnedWorkload ); } catch (error) { console.error("Return workload error:", error); return sendError(res, error.message || "Failed to return workload", 400); } } // Get pending approvals static async getMyPendingApprovals(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const pending = await WorkloadRPModel.getPendingApprovals( req.user.role, req.user.user_id ); return sendSuccess(res, "Pending approvals retrieved", pending); } catch (error) { console.error("Get pending approvals error:", error); return sendError(res, "Failed to retrieve pending approvals", 500); } } // Delete workload static async deleteWorkload(req, res) { try { const WorkloadRPModel = await getWorkloadRPModel(); const { id } = req.params; // Check if workload exists const workload = await WorkloadRPModel.findById(parseInt(id)); if (!workload) { return sendError(res, "Workload not found", 404); } // Check permissions if (!WorkloadRPController.canModifyWorkload(req.user, workload)) { return sendError(res, "You cannot delete this workload", 403); } // Only allow deletion of draft workloads if (workload.status !== "draft") { return sendError(res, "Only draft workloads can be deleted", 400); } await WorkloadRPModel.delete(parseInt(id)); return sendSuccess(res, "Workload deleted successfully"); } catch (error) { console.error("Delete workload error:", error); return sendError(res, "Failed to delete workload", 500); } } // ===== HELPER METHODS ===== // Format workload response according to column groups static formatWorkloadResponse(workload) { const total_course_load = (workload.each_section_course_load || 0) * (workload.number_of_sections || 1); const total_credit_hours = (workload.lecture_credit_hours || 0) + (workload.tutorial_credit_hours || 0) + (workload.lab_credit_hours || 0); const total_admin_load = (workload.elip_load || 0) + (workload.hdp_load || 0) + (workload.course_chair_load || 0) + (workload.section_advisor_load || 0) + (workload.advising_load || 0) + (workload.position_load || 0); return { workload_id: workload.workload_id, staff_info: { staff_id: workload.staff_id, first_name: workload.first_name, last_name: workload.last_name, employee_id: workload.employee_id, academic_rank: workload.academic_rank, staff_department: workload.staff_department, college_name: workload.college_name, }, // Course Details course_details: { course_code: workload.course_code, course_credit_hours: workload.course_credit_hours, lecture_credit_hours: workload.lecture_credit_hours, tutorial_credit_hours: workload.tutorial_credit_hours, lab_credit_hours: workload.lab_credit_hours, total_credit_hours: total_credit_hours, }, // Student Details student_details: { student_department: workload.student_department, academic_year: workload.academic_year, number_of_sections: workload.number_of_sections, }, // Load Calculation load_calculation: { each_section_course_load: workload.each_section_course_load, total_course_load: total_course_load, variety_of_course_load: workload.variety_of_course_load, research_load: workload.research_load, community_service_load: workload.community_service_load, }, // Administrative & Other Loads administrative_loads: { elip_load: workload.elip_load, hdp_load: workload.hdp_load, course_chair_load: workload.course_chair_load, section_advisor_load: workload.section_advisor_load, advising_load: workload.advising_load, position_load: workload.position_load, total_admin_load: total_admin_load, }, // Summary summary: { total_load: workload.total_load, over_payment_birr: workload.over_payment_birr, calculated_total: total_course_load + (workload.variety_of_course_load || 0) + (workload.research_load || 0) + (workload.community_service_load || 0) + total_admin_load, }, // Semester Info semester_info: { semester_id: workload.semester_id, semester_code: workload.semester_code, semester_name: workload.semester_name, academic_year: workload.year_name, }, // Status status: workload.status, validation: workload.validation, created_at: workload.created_at, updated_at: workload.updated_at, }; } // Calculate approval progress static async calculateApprovalProgress(workloadId) { const approvals = await query( "SELECT approver_role, status FROM approval_workflow WHERE entity_type = 'workload_rp' AND entity_id = ?", [workloadId] ); const workflowSteps = [ "department_head", "dean", "hr_director", "vpaa", "vpaf", "finance", ]; const totalSteps = workflowSteps.length; let completedSteps = 0; for (const step of workflowSteps) { const stepApproval = approvals.find((a) => a.approver_role === step); if (stepApproval && stepApproval.status === "approved") { completedSteps++; } } return { completed_steps: completedSteps, total_steps: totalSteps, percentage: Math.round((completedSteps / totalSteps) * 100), approvals, }; } // Helper methods for permissions static async getStaffIdFromUserId(userId) { try { const [staff] = await query( "SELECT staff_id FROM staff_profiles WHERE user_id = ?", [userId] ); return staff ? staff.staff_id : null; } catch (error) { console.error("Error getting staff ID:", error); return null; } } static async getUserDepartmentId(userId) { try { const [staff] = await query( "SELECT department_id FROM staff_profiles WHERE user_id = ?", [userId] ); return staff ? staff.department_id : null; } catch (error) { console.error("Error getting department ID:", error); return null; } } static async getUserCollegeId(userId) { try { const [college] = await query( `SELECT c.college_id FROM staff_profiles sp JOIN departments d ON sp.department_id = d.department_id JOIN colleges c ON d.college_id = c.college_id WHERE sp.user_id = ?`, [userId] ); return college ? college.college_id : null; } catch (error) { console.error("Error getting college ID:", error); return null; } } static canViewWorkload(user, workload) { if (user.role === "admin") return true; // Get user's staff_id if available if (["instructor", "department_head", "dean"].includes(user.role)) { // Simplified - in real implementation, check ownership return true; } return ["hr_director", "vpaa", "vpaf", "finance", "registrar"].includes( user.role ); } static canModifyWorkload(user, workload) { if (workload.status !== "draft") return false; if (user.role === "admin" || user.role === "hr_director") return true; if (["instructor", "department_head", "dean"].includes(user.role)) { return true; } return false; } static canSubmitWorkload(user, workload) { if (workload.status !== "draft") return false; if (["instructor", "department_head", "dean"].includes(user.role)) { return true; } return false; } static canApproveStep(user, approval) { return user.role === approval.approver_role; } static canRejectWorkload(user, workload) { return [ "department_head", "dean", "hr_director", "vpaa", "vpaf", "finance", ].includes(user.role); } static canReturnWorkload(user, workload) { return WorkloadRPController.canRejectWorkload(user, workload); } } export default WorkloadRPController; import { query } from "../config/database.js"; class OverloadDetectionService { // Detect overload for a specific staff member static async detectStaffOverload(staffId, semesterId) { try { // Get staff information const [staff] = await query( `SELECT sp.*, d.department_name, c.college_name FROM staff_profiles sp LEFT JOIN departments d ON sp.department_id = d.department_id LEFT JOIN colleges c ON d.college_id = c.college_id WHERE sp.staff_id = ?`, [staffId] ); if (!staff) { throw new Error("Staff not found"); } // Get rank limits const rankLimits = await this.getRankLimits(staff.academic_rank); // Calculate total workload const workloadSummary = await this.calculateTotalWorkload( staffId, semesterId ); // Check for overload const isOverloaded = workloadSummary.total_hours > rankLimits.max; const overloadHours = Math.max( 0, workloadSummary.total_hours - rankLimits.max ); // Calculate overload payment if applicable let overloadPayment = 0; if (isOverloaded) { const overloadRate = await this.getOverloadRate(); overloadPayment = overloadHours * overloadRate; } // Get detailed breakdown const breakdown = await this.getWorkloadBreakdown(staffId, semesterId); return { staff_id: staffId, staff_name: `${staff.first_name} ${staff.last_name}`, employee_id: staff.employee_id, academic_rank: staff.academic_rank, department: staff.department_name, college: staff.college_name, semester_id: semesterId, // Limits rank_limits: rankLimits, // Current workload current_workload: { total_hours: workloadSummary.total_hours, rp_hours: workloadSummary.rp_hours, assignments_hours: workloadSummary.assignments_hours, nrp_hours: workloadSummary.nrp_hours, overload_hours: overloadHours, }, // Status is_overloaded: isOverloaded, load_percentage: (workloadSummary.total_hours / rankLimits.max) * 100, status: this.getLoadStatus(workloadSummary.total_hours, rankLimits), // Overload details overload_details: { overload_hours: overloadHours, overload_rate: isOverloaded ? await this.getOverloadRate() : 0, estimated_payment: overloadPayment, requires_approval: overloadHours > 5, // Threshold for requiring special approval }, // Detailed breakdown breakdown: breakdown, // Recommendations recommendations: this.generateRecommendations( workloadSummary.total_hours, rankLimits, breakdown ), // Timestamp checked_at: new Date().toISOString(), }; } catch (error) { console.error("Detect staff overload error:", error); throw error; } } // Detect department-wide overload static async detectDepartmentOverload(departmentId, semesterId) { try { // Get all staff in department const staffList = await query( `SELECT sp.staff_id, sp.first_name, sp.last_name, sp.employee_id, sp.academic_rank FROM staff_profiles sp WHERE sp.department_id = ?`, [departmentId] ); const overloadReport = { department_id: departmentId, semester_id: semesterId, total_staff: staffList.length, overloaded_staff: 0, moderate_load_staff: 0, normal_load_staff: 0, underloaded_staff: 0, staff_details: [], summary: { total_overload_hours: 0, estimated_overload_payment: 0, average_load_percentage: 0, }, generated_at: new Date().toISOString(), }; let totalLoadPercentage = 0; const overloadRate = await this.getOverloadRate(); // Check each staff member for (const staff of staffList) { const staffOverload = await this.detectStaffOverload( staff.staff_id, semesterId ); overloadReport.staff_details.push({ staff_id: staff.staff_id, name: `${staff.first_name} ${staff.last_name}`, employee_id: staff.employee_id, academic_rank: staff.academic_rank, total_hours: staffOverload.current_workload.total_hours, max_hours: staffOverload.rank_limits.max, load_percentage: staffOverload.load_percentage, status: staffOverload.status, is_overloaded: staffOverload.is_overloaded, overload_hours: staffOverload.overload_details.overload_hours, estimated_payment: staffOverload.overload_details.estimated_payment, }); // Update counters totalLoadPercentage += staffOverload.load_percentage; if (staffOverload.is_overloaded) { overloadReport.overloaded_staff++; overloadReport.summary.total_overload_hours += staffOverload.overload_details.overload_hours; overloadReport.summary.estimated_overload_payment += staffOverload.overload_details.estimated_payment; } else if (staffOverload.load_percentage >= 80) { overloadReport.moderate_load_staff++; } else if (staffOverload.load_percentage >= 50) { overloadReport.normal_load_staff++; } else { overloadReport.underloaded_staff++; } } // Calculate averages overloadReport.summary.average_load_percentage = staffList.length > 0 ? totalLoadPercentage / staffList.length : 0; // Generate department recommendations overloadReport.recommendations = this.generateDepartmentRecommendations(overloadReport); return overloadReport; } catch (error) { console.error("Detect department overload error:", error); throw error; } } // Calculate total workload for staff static async calculateTotalWorkload(staffId, semesterId) { try { let totalHours = 0; let rpHours = 0; let assignmentsHours = 0; let nrpHours = 0; // 1. Regular Program (RP) workload const [rpWorkload] = await query( `SELECT COALESCE(SUM(total_load), 0) as total FROM workload_rp WHERE staff_id = ? AND semester_id = ? AND status NOT IN ('rejected', 'draft')`, [staffId, semesterId] ); rpHours = parseFloat(rpWorkload.total || 0); totalHours += rpHours; // 2. Course assignments (accepted) const assignments = await query( `SELECT ca.*, c.credit_hours FROM course_assignments ca LEFT JOIN courses c ON ca.course_id = c.course_id WHERE ca.staff_id = ? AND ca.semester_id = ? AND ca.status = 'accepted'`, [staffId, semesterId] ); for (const assignment of assignments) { const assignmentHours = assignment.credit_hours * 1.5; // Load factor assignmentsHours += assignmentHours; totalHours += assignmentHours; } // 3. Non-Regular Program (NRP) workload (convert payment to hours) const [nrpWorkload] = await query( `SELECT COALESCE(SUM(total_hours_worked), 0) as total_hours FROM workload_nrp WHERE staff_id = ? AND semester_id = ? AND status NOT IN ('rejected', 'draft')`, [staffId, semesterId] ); nrpHours = parseFloat(nrpWorkload.total_hours || 0); totalHours += nrpHours; // 4. Administrative duties (from workload_rp) const [adminDuties] = await query( `SELECT COALESCE(SUM(elip_load), 0) as elip, COALESCE(SUM(hdp_load), 0) as hdp, COALESCE(SUM(course_chair_load), 0) as course_chair, COALESCE(SUM(section_advisor_load), 0) as section_advisor, COALESCE(SUM(advising_load), 0) as advising, COALESCE(SUM(position_load), 0) as position FROM workload_rp WHERE staff_id = ? AND semester_id = ?`, [staffId, semesterId] ); const adminHours = parseFloat(adminDuties.elip || 0) + parseFloat(adminDuties.hdp || 0) + parseFloat(adminDuties.course_chair || 0) + parseFloat(adminDuties.section_advisor || 0) + parseFloat(adminDuties.advising || 0) + parseFloat(adminDuties.position || 0); totalHours += adminHours; return { total_hours: parseFloat(totalHours.toFixed(2)), rp_hours: parseFloat(rpHours.toFixed(2)), assignments_hours: parseFloat(assignmentsHours.toFixed(2)), nrp_hours: parseFloat(nrpHours.toFixed(2)), admin_hours: parseFloat(adminHours.toFixed(2)), assignment_count: assignments.length, }; } catch (error) { console.error("Calculate total workload error:", error); return { total_hours: 0, rp_hours: 0, assignments_hours: 0, nrp_hours: 0, admin_hours: 0, assignment_count: 0, }; } } // Get detailed workload breakdown static async getWorkloadBreakdown(staffId, semesterId) { try { const breakdown = { regular_program: [], course_assignments: [], non_regular_program: [], administrative_duties: [], }; // Regular Program courses const rpCourses = await query( `SELECT course_code, total_load, status FROM workload_rp WHERE staff_id = ? AND semester_id = ? AND status NOT IN ('rejected', 'draft') ORDER BY total_load DESC`, [staffId, semesterId] ); breakdown.regular_program = rpCourses; // Course assignments const assignments = await query( `SELECT ca.*, c.course_code, c.course_title, c.credit_hours FROM course_assignments ca LEFT JOIN courses c ON ca.course_id = c.course_id WHERE ca.staff_id = ? AND ca.semester_id = ? AND ca.status = 'accepted' ORDER BY c.course_code`, [staffId, semesterId] ); breakdown.course_assignments = assignments.map((a) => ({ ...a, estimated_load: a.credit_hours * 1.5, })); // Non-Regular Program const nrpCourses = await query( `SELECT program_type, course_code, total_hours_worked, total_payment, status FROM workload_nrp WHERE staff_id = ? AND semester_id = ? AND status NOT IN ('rejected', 'draft') ORDER BY total_hours_worked DESC`, [staffId, semesterId] ); breakdown.non_regular_program = nrpCourses; // Administrative duties const [adminDetails] = await query( `SELECT COALESCE(SUM(elip_load), 0) as elip, COALESCE(SUM(hdp_load), 0) as hdp, COALESCE(SUM(course_chair_load), 0) as course_chair, COALESCE(SUM(section_advisor_load), 0) as section_advisor, COALESCE(SUM(advising_load), 0) as advising, COALESCE(SUM(position_load), 0) as position FROM workload_rp WHERE staff_id = ? AND semester_id = ?`, [staffId, semesterId] ); breakdown.administrative_duties = [ { type: "ELIP", hours: parseFloat(adminDetails.elip || 0) }, { type: "HDP", hours: parseFloat(adminDetails.hdp || 0) }, { type: "Course Chair", hours: parseFloat(adminDetails.course_chair || 0), }, { type: "Section Advisor", hours: parseFloat(adminDetails.section_advisor || 0), }, { type: "Advising", hours: parseFloat(adminDetails.advising || 0) }, { type: "Position", hours: parseFloat(adminDetails.position || 0) }, ].filter((d) => d.hours > 0); return breakdown; } catch (error) { console.error("Get workload breakdown error:", error); return { regular_program: [], course_assignments: [], non_regular_program: [], administrative_duties: [], }; } } // Get rank limits static async getRankLimits(academicRank) { try { const [minRule] = await query( `SELECT rule_value FROM system_rules WHERE rule_name = CONCAT('rank_min_', ?) AND (effective_to IS NULL OR effective_to >= CURDATE())`, [academicRank] ); const [maxRule] = await query( `SELECT rule_value FROM system_rules WHERE rule_name = CONCAT('rank_max_', ?) AND (effective_to IS NULL OR effective_to >= CURDATE())`, [academicRank] ); return { min: minRule ? parseFloat(minRule.rule_value) : 0, max: maxRule ? parseFloat(maxRule.rule_value) : 0, }; } catch (error) { console.error("Get rank limits error:", error); // Default limits const defaultLimits = { graduate_assistant: { min: 12, max: 16 }, assistant_lecturer: { min: 10, max: 14 }, lecturer: { min: 8, max: 12 }, assistant_professor: { min: 6, max: 10 }, associate_professor: { min: 4, max: 8 }, professor: { min: 4, max: 6 }, }; return defaultLimits[academicRank] || { min: 8, max: 12 }; } } // Get overload rate static async getOverloadRate() { try { const [rateRule] = await query( `SELECT rule_value FROM system_rules WHERE rule_name = 'overload_rate' AND (effective_to IS NULL OR effective_to >= CURDATE()) ORDER BY effective_from DESC LIMIT 1` ); return rateRule ? parseFloat(rateRule.rule_value) : 450; } catch (error) { console.error("Get overload rate error:", error); return 450; // Default rate } } // Get load status static getLoadStatus(totalHours, limits) { const percentage = (totalHours / limits.max) * 100; if (totalHours <= 0) return "No Load"; if (percentage < 50) return "Underloaded"; if (percentage < 80) return "Normal"; if (percentage < 100) return "High Load"; if (percentage < 120) return "Moderate Overload"; if (percentage < 150) return "High Overload"; return "Critical Overload"; } // Generate recommendations static generateRecommendations(totalHours, limits, breakdown) { const recommendations = []; const percentage = (totalHours / limits.max) * 100; if (percentage < 50) { recommendations.push( "Consider requesting additional courses to meet minimum requirements" ); recommendations.push( "Check with department head for available teaching opportunities" ); } else if (percentage >= 100) { recommendations.push("Reduce teaching load to stay within rank limits"); recommendations.push("Consider delegating administrative duties"); recommendations.push( "Request overload payment approval if continuing with current load" ); // Specific recommendations based on breakdown if (breakdown.administrative_duties.length > 3) { recommendations.push( "Consider reducing administrative duties (currently have " + breakdown.administrative_duties.length + " types)" ); } const highLoadCourses = breakdown.regular_program.filter( (c) => c.total_load > 3 ); if (highLoadCourses.length > 0) { recommendations.push( "High-load courses detected. Consider splitting or reducing credit hours" ); } } else if (percentage >= 80) { recommendations.push( "Monitor workload carefully - approaching overload threshold" ); recommendations.push("Consider workload distribution for next semester"); } // Check for imbalanced distribution if (breakdown.regular_program.length > 4) { recommendations.push( "Teaching many different courses may increase preparation time" ); } return recommendations; } // Generate department recommendations static generateDepartmentRecommendations(report) { const recommendations = []; if (report.overloaded_staff > 0) { recommendations.push( `${report.overloaded_staff} staff members are overloaded. Review their assignments.` ); if (report.overloaded_staff > report.staff_details.length * 0.3) { recommendations.push( "High percentage of overloaded staff. Consider hiring additional instructors or adjusting course offerings." ); } } if (report.underloaded_staff > 0) { recommendations.push( `${report.underloaded_staff} staff members are underloaded. Consider redistributing courses.` ); } if (report.summary.average_load_percentage > 90) { recommendations.push( "Department average load is high. Monitor overall department capacity." ); } if (report.summary.estimated_overload_payment > 10000) { recommendations.push( `Significant overload payments estimated (${report.summary.estimated_overload_payment.toFixed( 2 )} Birr). Consider budget implications.` ); } // Identify staff with extreme loads const extremeLoads = report.staff_details.filter( (s) => s.load_percentage > 150 ); if (extremeLoads.length > 0) { recommendations.push( `${extremeLoads.length} staff members have critical overload. Immediate review required.` ); } return recommendations; } // Predict future overload based on trends static async predictOverloadTrend(staffId, upcomingSemesterId) { try { // Get current semester workload const [currentSemester] = await query( "SELECT semester_id FROM semesters WHERE is_active = TRUE LIMIT 1" ); if (!currentSemester) { throw new Error("No active semester found"); } const currentWorkload = await this.calculateTotalWorkload( staffId, currentSemester.semester_id ); const staff = await query( "SELECT academic_rank FROM staff_profiles WHERE staff_id = ?", [staffId] ); if (!staff[0]) { throw new Error("Staff not found"); } const rankLimits = await this.getRankLimits(staff[0].academic_rank); // Get historical trend (last 3 semesters) const historicalSemesters = await query( `SELECT s.semester_id, s.semester_code, s.semester_name FROM semesters s WHERE s.semester_id != ? AND s.end_date < CURDATE() ORDER BY s.end_date DESC LIMIT 3`, [currentSemester.semester_id] ); const historicalWorkloads = []; for (const semester of historicalSemesters) { const workload = await this.calculateTotalWorkload( staffId, semester.semester_id ); historicalWorkloads.push({ semester: semester.semester_code, total_hours: workload.total_hours, }); } // Calculate trend let trend = "stable"; if (historicalWorkloads.length >= 2) { const recentChange = historicalWorkloads[0].total_hours - (historicalWorkloads[1]?.total_hours || historicalWorkloads[0].total_hours); if (recentChange > 2) trend = "increasing"; else if (recentChange < -2) trend = "decreasing"; } // Predict based on trend let predictedHours = currentWorkload.total_hours; if (trend === "increasing") { predictedHours *= 1.1; // 10% increase } else if (trend === "decreasing") { predictedHours *= 0.9; // 10% decrease } const predictedOverload = predictedHours > rankLimits.max; const predictedOverloadHours = Math.max( 0, predictedHours - rankLimits.max ); return { staff_id: staffId, current_semester: currentSemester.semester_id, upcoming_semester: upcomingSemesterId, current_workload: currentWorkload.total_hours, predicted_workload: parseFloat(predictedHours.toFixed(2)), rank_limit: rankLimits.max, trend: trend, predicted_overload: predictedOverload, predicted_overload_hours: parseFloat(predictedOverloadHours.toFixed(2)), confidence: historicalWorkloads.length > 1 ? "medium" : "low", historical_data: historicalWorkloads, recommendation: predictedOverload ? "Consider reducing workload for upcoming semester" : "Current trend suggests manageable workload", }; } catch (error) { console.error("Predict overload trend error:", error); throw error; } } // Generate overload report for approval static async generateOverloadReport(staffId, semesterId) { const overloadData = await this.detectStaffOverload(staffId, semesterId); if (!overloadData.is_overloaded) { return { requires_report: false, message: "No overload detected", }; } const report = { report_type: "overload_detection", staff_id: staffId, semester_id: semesterId, generated_date: new Date().toISOString(), data: overloadData, // Approval workflow approval_required: overloadData.overload_details.requires_approval, approval_steps: [ { role: "department_head", status: "pending", required: true }, { role: "dean", status: "pending", required: overloadData.overload_details.overload_hours > 10, }, { role: "hr_director", status: "pending", required: true }, { role: "finance", status: "pending", required: true }, ], // Financial details financial_summary: { overload_hours: overloadData.overload_details.overload_hours, rate_per_hour: overloadData.overload_details.overload_rate, gross_amount: overloadData.overload_details.estimated_payment, tax_rate: 10, // Default tax rate tax_amount: overloadData.overload_details.estimated_payment * 0.1, net_amount: overloadData.overload_details.estimated_payment * 0.9, }, // Justification required justification_required: true, justification_fields: [ "reason_for_overload", "alternative_options_considered", "duration_of_overload", "impact_on_other_duties", ], }; return report; } } export default OverloadDetectionService; // src/services/WorkloadNRPService.js import { query } from "../config/database.js"; class WorkloadNRPService { // Calculate payment for NRP workload static async calculatePayment(workloadData) { const { program_type, credit_hours = 0, lecture_credit_hours = 0, lab_credit_hours = 0, tutorial_credit_hours = 0, teaching_hours = 0, module_hours = 0, // tutorial_sessions = 0, assignment_students = 0, exam_students = 0, project_groups = 0, student_count = 0, rate_category = "default", academic_rank, is_overload = false, overload_hours = 0, } = workloadData; let totalPayment = 0; let teachingPayment = 0; let tutorialPayment = 0; let assignmentPayment = 0; let examPayment = 0; let projectPayment = 0; let overloadPayment = 0; // Get rates from database const [rate] = await query( `SELECT * FROM rate_tables WHERE program_type = ? AND (rate_category = ? OR rate_category = 'default') AND (effective_to IS NULL OR effective_to >= CURDATE()) ORDER BY rate_category DESC LIMIT 1`, [program_type, rate_category] ); // Get tax rate const [taxRule] = await query( `SELECT tax_rate FROM tax_rules WHERE program_type = ? AND (effective_to IS NULL OR effective_to >= CURDATE()) ORDER BY effective_from DESC LIMIT 1`, [program_type] ); const taxRate = taxRule?.tax_rate || 10.0; // Default 10% switch (program_type) { case "extension": case "weekend": // Payment based on credit hours const ratePerCredit = rate?.amount_per_credit || 500; const totalCredits = credit_hours || lecture_credit_hours + lab_credit_hours + tutorial_credit_hours; teachingPayment = totalCredits * ratePerCredit; // Additional payments for assignments and exams assignmentPayment = assignment_students * (rate?.assignment_rate || 25); examPayment = exam_students * (rate?.exam_rate || 20); totalPayment = teachingPayment + assignmentPayment + examPayment; break; case "summer": // Payment based on teaching hours const ratePerHour = rate?.amount_per_hour || 450; teachingPayment = teaching_hours * ratePerHour; // Tutorial payments tutorialPayment = 0; // Assignment and exam corrections assignmentPayment = assignment_students * (rate?.assignment_rate || 25); examPayment = exam_students * (rate?.exam_rate || 20); totalPayment = teachingPayment + tutorialPayment + assignmentPayment + examPayment; break; case "distance": // Payment based on module hours const moduleRatePerHour = rate?.amount_per_hour || 520; teachingPayment = module_hours * moduleRatePerHour; // Student-based payment const studentRate = rate?.amount_per_student || 10; assignmentPayment = student_count * studentRate; totalPayment = teachingPayment + assignmentPayment; break; default: throw new Error(`Unsupported program type: ${program_type}`); } // Calculate overload payment if applicable if (is_overload && overload_hours > 0) { const [overloadRate] = await query( `SELECT rule_value FROM system_rules WHERE rule_name = 'overload_rate' AND (effective_to IS NULL OR effective_to >= CURDATE()) ORDER BY effective_from DESC LIMIT 1` ); const overloadRatePerHour = parseFloat(overloadRate?.rule_value) || 450; overloadPayment = overload_hours * overloadRatePerHour; totalPayment += overloadPayment; } return { teaching_payment: teachingPayment, tutorial_payment: tutorialPayment, assignment_payment: assignmentPayment, exam_payment: examPayment, project_payment: projectPayment, overload_payment: overloadPayment, total_payment: totalPayment }; } // Validate NRP workload static async validateWorkload(workloadData) { const errors = []; const warnings = []; // Required fields validation if (!workloadData.staff_id) { errors.push("Staff ID is required"); } if (!workloadData.semester_id) { errors.push("Semester ID is required"); } if (!workloadData.program_type) { errors.push("Program type is required"); } if (!workloadData.course_code && !workloadData.course_title) { warnings.push("Course code or title is recommended"); } // Hours validation if (workloadData.credit_hours < 0) { errors.push("Credit hours cannot be negative"); } if (workloadData.teaching_hours < 0) { errors.push("Teaching hours cannot be negative"); } if (workloadData.student_count < 0) { errors.push("Student count cannot be negative"); } // Check if staff exists const [staff] = await query( "SELECT staff_id FROM staff_profiles WHERE staff_id = ?", [workloadData.staff_id] ); if (!staff) { errors.push("Staff member not found"); } // Check if semester exists const [semester] = await query( "SELECT semester_id FROM semesters WHERE semester_id = ?", [workloadData.semester_id] ); if (!semester) { errors.push("Semester not found"); } // Check for duplicate workload (same staff, semester, program, course) if (workloadData.course_code) { const [existing] = await query( `SELECT nrp_id FROM workload_nrp WHERE staff_id = ? AND semester_id = ? AND program_type = ? AND course_code = ? AND status NOT IN ('rejected', 'draft')`, [ workloadData.staff_id, workloadData.semester_id, workloadData.program_type, workloadData.course_code, ] ); if (existing) { warnings.push("Similar workload already exists for this course"); } } return { valid: errors.length === 0, errors, warnings, }; } // Generate contract number static async generateContractNumber(programType, semesterId) { const [semester] = await query( "SELECT semester_code FROM semesters WHERE semester_id = ?", [semesterId] ); const prefixMap = { extension: "EXT", weekend: "WKD", summer: "SUM", distance: "DST", }; const prefix = prefixMap[programType] || "NRP"; const semesterCode = semester?.semester_code || "UNKN"; const timestamp = Date.now().toString().slice(-6); return `${prefix}-${semesterCode}-${timestamp}`; } // Get NRP dashboard statistics static async getDashboardStats(userRole, userId = null, filters = {}) { let whereClause = "WHERE 1=1"; const params = []; // Role-based filtering if (userRole === "department_head") { const [staff] = await query( "SELECT department_id FROM staff_profiles WHERE user_id = ?", [userId] ); if (staff?.department_id) { whereClause += ` AND sp.department_id = ?`; params.push(staff.department_id); } } else if (userRole === "dean") { const [college] = await query( `SELECT c.college_id FROM colleges c JOIN departments d ON c.college_id = d.college_id JOIN staff_profiles sp ON d.department_id = sp.department_id WHERE sp.user_id = ?`, [userId] ); if (college?.college_id) { whereClause += ` AND c.college_id = ?`; params.push(college.college_id); } } // Additional filters if (filters.semester_id) { whereClause += " AND wn.semester_id = ?"; params.push(filters.semester_id); } if (filters.program_type) { whereClause += " AND wn.program_type = ?"; params.push(filters.program_type); } if (filters.status) { whereClause += " AND wn.status = ?"; params.push(filters.status); } if (filters.date_from) { whereClause += " AND wn.created_at >= ?"; params.push(filters.date_from); } if (filters.date_to) { whereClause += " AND wn.created_at <= ?"; params.push(filters.date_to); } const stats = await query( `SELECT -- Counts COUNT(*) as total_workloads, COUNT(CASE WHEN wn.status = 'draft' THEN 1 END) as draft_count, COUNT(CASE WHEN wn.status = 'submitted' THEN 1 END) as submitted_count, COUNT(CASE WHEN wn.status = 'finance_approved' THEN 1 END) as approved_count, COUNT(CASE WHEN wn.status = 'paid' THEN 1 END) as paid_count, -- Financials COALESCE(SUM(wn.total_payment), 0) as total_payments, COALESCE(AVG(wn.total_payment), 0) as average_payment, -- Program breakdown COUNT(CASE WHEN wn.program_type = 'extension' THEN 1 END) as extension_count, COUNT(CASE WHEN wn.program_type = 'weekend' THEN 1 END) as weekend_count, COUNT(CASE WHEN wn.program_type = 'summer' THEN 1 END) as summer_count, COUNT(CASE WHEN wn.program_type = 'distance' THEN 1 END) as distance_count, -- Staff statistics COUNT(DISTINCT wn.staff_id) as unique_staff, COUNT(DISTINCT sp.department_id) as departments_involved FROM workload_nrp wn LEFT JOIN staff_profiles sp ON wn.staff_id = sp.staff_id LEFT JOIN departments d ON sp.department_id = d.department_id LEFT JOIN colleges c ON d.college_id = c.college_id ${whereClause}`, params ); return stats[0] || {}; } // Calculate total hours worked static calculateTotalHours(workloadData) { const { teaching_hours = 0, module_hours = 0, // tutorial_sessions = 0, overload_hours = 0, } = workloadData; // Assuming each tutorial session is 2 hours const tutorialHours = 0; return teaching_hours + module_hours + tutorialHours + overload_hours; } // Get rate based on academic rank static async getRankRate(academicRank, programType) { const rankRateMap = { professor: { A: 600, B: 550, C: 500 }, associate_professor: { A: 550, B: 500, C: 450 }, assistant_professor: { A: 500, B: 450, C: 400 }, lecturer: { A: 450, B: 400, C: 350 }, assistant_lecturer: { A: 400, B: 350, C: 300 }, graduate_assistant: { A: 350, B: 300, C: 250 }, }; // Get default rates from database const [defaultRate] = await query( `SELECT amount_per_credit, amount_per_hour FROM rate_tables WHERE program_type = ? AND rate_category = 'default' AND (effective_to IS NULL OR effective_to >= CURDATE()) ORDER BY effective_from DESC LIMIT 1`, [programType] ); const rankRates = rankRateMap[academicRank] || { A: 450, B: 400, C: 350 }; return { rank_rates: rankRates, default_rate: defaultRate, }; } } export default WorkloadNRPService;// src/services/WorkloadReportService.js import { query } from "../config/database.js"; import { PROGRAM_TYPES, NRP_PROGRAM_TYPES, WORKLOAD_STATUSES, } from "../config/constants.js"; import moment from "moment"; class WorkloadReportService { // Generate comprehensive workload report static async generateComprehensiveReport(filters = {}) { try { const { semester_id, department_id, college_id, staff_id, program_type, status, date_from, date_to, report_type = "comprehensive", } = filters; console.log(`📊 Generating comprehensive report with filters:`, filters); // Build base WHERE clause let whereClause = `WHERE 1=1`; const params = []; if (semester_id) { whereClause += ` AND s.semester_id = ?`; params.push(semester_id); } if (department_id) { whereClause += ` AND sp.department_id = ?`; params.push(department_id); } if (college_id) { whereClause += ` AND d.college_id = ?`; params.push(college_id); } if (staff_id) { whereClause += ` AND sp.staff_id = ?`; params.push(staff_id); } if (program_type) { whereClause += ` AND wn.program_type = ?`; params.push(program_type); } if (status) { whereClause += ` AND wr.status = ?`; params.push(status); } if (date_from) { whereClause += ` AND wr.created_at >= ?`; params.push(date_from); } if (date_to) { whereClause += ` AND wr.created_at <= ?`; params.push(date_to); } // 1. RP Workload Data const rpWorkloads = await query( ` SELECT wr.workload_id, wr.staff_id, wr.semester_id, wr.course_code, wr.course_credit_hours, wr.lecture_credit_hours, wr.tutorial_credit_hours, wr.lab_credit_hours, wr.student_department, wr.academic_year, wr.number_of_sections, wr.each_section_course_load, wr.variety_of_course_load, wr.research_load, wr.community_service_load, wr.elip_load, wr.hdp_load, wr.course_chair_load, wr.section_advisor_load, wr.advising_load, wr.position_load, wr.total_load, wr.over_payment_birr, wr.status, wr.created_at, sp.first_name, sp.last_name, sp.employee_id, sp.academic_rank, d.department_name, d.department_code, c.college_name, c.college_code, s.semester_code, s.semester_name, ay.year_name, ay.year_code FROM workload_rp wr JOIN staff_profiles sp ON wr.staff_id = sp.staff_id JOIN departments d ON sp.department_id = d.department_id JOIN colleges c ON d.college_id = c.college_id JOIN semesters s ON wr.semester_id = s.semester_id JOIN academic_years ay ON s.academic_year_id = ay.academic_year_id ${whereClause} ORDER BY wr.created_at DESC `, params ); // 2. NRP Workload Data const nrpWorkloads = await query( ` SELECT wn.nrp_id, wn.staff_id, wn.semester_id, wn.program_type, wn.contract_number, wn.academic_year, wn.course_id, wn.course_code, wn.course_title, wn.credit_hours, wn.lecture_credit_hours, wn.lab_credit_hours, wn.tutorial_credit_hours, wn.teaching_hours, wn.module_hours, wn.student_count, wn.assignment_students, wn.exam_students, wn.rate_category, wn.teaching_payment, wn.tutorial_payment, wn.assignment_payment, wn.exam_payment, wn.project_payment, wn.total_payment, wn.total_hours_worked, wn.contract_duration_from, wn.contract_duration_to, wn.is_overload, wn.overload_hours, wn.overload_payment, wn.status, wn.created_at, sp.first_name, sp.last_name, sp.employee_id, sp.academic_rank, d.department_name, d.department_code, c.college_name, c.college_code, s.semester_code, s.semester_name, ay.year_name, ay.year_code, cr.course_title as actual_course_title FROM workload_nrp wn JOIN staff_profiles sp ON wn.staff_id = sp.staff_id JOIN departments d ON sp.department_id = d.department_id JOIN colleges c ON d.college_id = c.college_id JOIN semesters s ON wn.semester_id = s.semester_id JOIN academic_years ay ON s.academic_year_id = ay.academic_year_id LEFT JOIN courses cr ON wn.course_id = cr.course_id ${whereClause.replace("wr.", "wn.")} ORDER BY wn.created_at DESC `, params ); // 3. Course Assignments const assignments = await query( ` SELECT ca.*, c.course_code, c.course_title, c.credit_hours, sp.first_name, sp.last_name, sp.employee_id, s.semester_code, s.semester_name FROM course_assignments ca JOIN courses c ON ca.course_id = c.course_id JOIN staff_profiles sp ON ca.staff_id = sp.staff_id JOIN semesters s ON ca.semester_id = s.semester_id WHERE ca.semester_id = IFNULL(?, ca.semester_id) ORDER BY ca.assigned_date DESC `, [semester_id || null] ); // 4. Calculate Statistics const statistics = await this.calculateStatistics( rpWorkloads, nrpWorkloads, assignments ); // 5. Generate Summary const summary = { report_type, generated_at: new Date().toISOString(), filters, statistics, breakdown: { by_department: await this.breakdownByDepartment( rpWorkloads, nrpWorkloads ), by_program: await this.breakdownByProgram(nrpWorkloads), by_status: await this.breakdownByStatus(rpWorkloads, nrpWorkloads), by_academic_rank: await this.breakdownByAcademicRank( rpWorkloads, nrpWorkloads ), }, trends: await this.calculateTrends(semester_id, department_id), recommendations: await this.generateRecommendations(statistics), }; return { success: true, report: summary, data: { rp_workloads: rpWorkloads, nrp_workloads: nrpWorkloads, assignments: assignments, }, metadata: { total_records: rpWorkloads.length + nrpWorkloads.length + assignments.length, rp_count: rpWorkloads.length, nrp_count: nrpWorkloads.length, assignment_count: assignments.length, export_formats: ["pdf", "excel", "csv", "json"], }, }; } catch (error) { console.error("Error generating comprehensive report:", error); throw new Error(`Failed to generate report: ${error.message}`); } } // Calculate comprehensive statistics static async calculateStatistics(rpWorkloads, nrpWorkloads, assignments) { // RP Statistics const rpStats = { total_workloads: rpWorkloads.length, total_hours: rpWorkloads.reduce( (sum, w) => sum + (parseFloat(w.total_load) || 0), 0 ), total_over_payment: rpWorkloads.reduce( (sum, w) => sum + (parseFloat(w.over_payment_birr) || 0), 0 ), average_load: rpWorkloads.length > 0 ? rpWorkloads.reduce( (sum, w) => sum + (parseFloat(w.total_load) || 0), 0 ) / rpWorkloads.length : 0, by_status: {}, by_department: {}, by_rank: {}, }; // NRP Statistics const nrpStats = { total_workloads: nrpWorkloads.length, total_hours: nrpWorkloads.reduce( (sum, w) => sum + (parseFloat(w.total_hours_worked) || 0), 0 ), total_payment: nrpWorkloads.reduce( (sum, w) => sum + (parseFloat(w.total_payment) || 0), 0 ), average_payment: nrpWorkloads.length > 0 ? nrpWorkloads.reduce( (sum, w) => sum + (parseFloat(w.total_payment) || 0), 0 ) / nrpWorkloads.length : 0, by_program: {}, by_status: {}, by_contract_type: {}, }; // Assignment Statistics const assignmentStats = { total_assignments: assignments.length, accepted: assignments.filter((a) => a.status === "accepted").length, pending: assignments.filter((a) => a.status === "assigned").length, declined: assignments.filter((a) => a.status === "declined").length, by_course: {}, by_staff: {}, }; // Calculate breakdowns // RP by status rpWorkloads.forEach((w) => { rpStats.by_status[w.status] = (rpStats.by_status[w.status] || 0) + 1; rpStats.by_department[w.department_name] = (rpStats.by_department[w.department_name] || 0) + 1; rpStats.by_rank[w.academic_rank] = (rpStats.by_rank[w.academic_rank] || 0) + 1; }); // NRP by program nrpWorkloads.forEach((w) => { nrpStats.by_program[w.program_type] = (nrpStats.by_program[w.program_type] || 0) + 1; nrpStats.by_status[w.status] = (nrpStats.by_status[w.status] || 0) + 1; }); // Overall Statistics const overallStats = { total_hours: rpStats.total_hours + nrpStats.total_hours, total_payment: nrpStats.total_payment + rpStats.total_over_payment, total_workloads: rpStats.total_workloads + nrpStats.total_workloads, average_hours_per_staff: 0, staff_count: new Set([ ...rpWorkloads.map((w) => w.staff_id), ...nrpWorkloads.map((w) => w.staff_id), ]).size, department_count: new Set([ ...rpWorkloads.map((w) => w.department_id), ...nrpWorkloads.map((w) => w.department_id), ]).size, }; if (overallStats.staff_count > 0) { overallStats.average_hours_per_staff = overallStats.total_hours / overallStats.staff_count; } return { rp: rpStats, nrp: nrpStats, assignments: assignmentStats, overall: overallStats, }; } // Breakdown by department static async breakdownByDepartment(rpWorkloads, nrpWorkloads) { const departments = {}; // Combine RP and NRP workloads const allWorkloads = [ ...rpWorkloads.map((w) => ({ ...w, type: "RP" })), ...nrpWorkloads.map((w) => ({ ...w, type: "NRP" })), ]; allWorkloads.forEach((workload) => { const deptName = workload.department_name; if (!departments[deptName]) { departments[deptName] = { department_name: deptName, department_code: workload.department_code, rp_count: 0, nrp_count: 0, total_hours: 0, total_payment: 0, staff_count: new Set(), }; } const dept = departments[deptName]; dept.staff_count.add(workload.staff_id); if (workload.type === "RP") { dept.rp_count++; dept.total_hours += parseFloat(workload.total_load) || 0; dept.total_payment += parseFloat(workload.over_payment_birr) || 0; } else { dept.nrp_count++; dept.total_hours += parseFloat(workload.total_hours_worked) || 0; dept.total_payment += parseFloat(workload.total_payment) || 0; } }); // Convert to array and calculate averages return Object.values(departments).map((dept) => ({ ...dept, staff_count: dept.staff_count.size, average_hours_per_staff: dept.staff_count.size > 0 ? dept.total_hours / dept.staff_count.size : 0, })); } // Breakdown by program type static async breakdownByProgram(nrpWorkloads) { const programs = {}; nrpWorkloads.forEach((workload) => { const programType = workload.program_type; if (!programs[programType]) { programs[programType] = { program_type: programType, workload_count: 0, total_hours: 0, total_payment: 0, staff_count: new Set(), average_payment: 0, courses: new Set(), }; } const program = programs[programType]; program.workload_count++; program.total_hours += parseFloat(workload.total_hours_worked) || 0; program.total_payment += parseFloat(workload.total_payment) || 0; program.staff_count.add(workload.staff_id); if (workload.course_code) { program.courses.add(workload.course_code); } }); // Convert to array return Object.values(programs).map((program) => ({ ...program, staff_count: program.staff_count.size, course_count: program.courses.size, average_payment_per_workload: program.workload_count > 0 ? program.total_payment / program.workload_count : 0, average_hours_per_workload: program.workload_count > 0 ? program.total_hours / program.workload_count : 0, })); } // Breakdown by status static async breakdownByStatus(rpWorkloads, nrpWorkloads) { const statusBreakdown = {}; // Process RP workloads rpWorkloads.forEach((workload) => { const status = workload.status; if (!statusBreakdown[status]) { statusBreakdown[status] = { status: status, rp_count: 0, nrp_count: 0, total_count: 0, }; } statusBreakdown[status].rp_count++; statusBreakdown[status].total_count++; }); // Process NRP workloads nrpWorkloads.forEach((workload) => { const status = workload.status; if (!statusBreakdown[status]) { statusBreakdown[status] = { status: status, rp_count: 0, nrp_count: 0, total_count: 0, }; } statusBreakdown[status].nrp_count++; statusBreakdown[status].total_count++; }); return Object.values(statusBreakdown); } // Breakdown by academic rank static async breakdownByAcademicRank(rpWorkloads, nrpWorkloads) { const ranks = {}; // Combine workloads const allWorkloads = [...rpWorkloads, ...nrpWorkloads]; allWorkloads.forEach((workload) => { const rank = workload.academic_rank; if (!ranks[rank]) { ranks[rank] = { academic_rank: rank, staff_count: new Set(), workload_count: 0, total_hours: 0, average_hours: 0, }; } ranks[rank].staff_count.add(workload.staff_id); ranks[rank].workload_count++; // Add hours based on workload type if ("total_load" in workload) { ranks[rank].total_hours += parseFloat(workload.total_load) || 0; } else if ("total_hours_worked" in workload) { ranks[rank].total_hours += parseFloat(workload.total_hours_worked) || 0; } }); // Calculate averages return Object.values(ranks).map((rank) => ({ ...rank, staff_count: rank.staff_count.size, average_hours_per_staff: rank.staff_count.size > 0 ? rank.total_hours / rank.staff_count.size : 0, average_hours_per_workload: rank.workload_count > 0 ? rank.total_hours / rank.workload_count : 0, })); } // Calculate trends static async calculateTrends(semester_id, department_id) { try { const trends = { monthly_trend: [], semester_comparison: [], department_comparison: [], }; // Get last 6 months trend const sixMonthsAgo = moment().subtract(6, "months").format("YYYY-MM-DD"); const monthlyTrend = await query( ` SELECT DATE_FORMAT(created_at, '%Y-%m') as month, COUNT(*) as workload_count, SUM(total_load) as total_hours FROM workload_rp WHERE created_at >= ? GROUP BY DATE_FORMAT(created_at, '%Y-%m') ORDER BY month `, [sixMonthsAgo] ); trends.monthly_trend = monthlyTrend; // Semester comparison const semesterComparison = await query(` SELECT s.semester_name, COUNT(wr.workload_id) as workload_count, COALESCE(SUM(wr.total_load), 0) as total_hours, COALESCE(AVG(wr.total_load), 0) as average_hours FROM semesters s LEFT JOIN workload_rp wr ON s.semester_id = wr.semester_id WHERE s.start_date >= DATE_SUB(NOW(), INTERVAL 1 YEAR) GROUP BY s.semester_id, s.semester_name ORDER BY s.start_date DESC `); trends.semester_comparison = semesterComparison; return trends; } catch (error) { console.error("Error calculating trends:", error); return { monthly_trend: [], semester_comparison: [], department_comparison: [], }; } } // Generate recommendations based on statistics static async generateRecommendations(statistics) { const recommendations = []; // Check for overload const averageHoursPerStaff = statistics.overall.average_hours_per_staff || 0; if (averageHoursPerStaff > 12) { recommendations.push({ type: "warning", title: "High Average Workload", message: `Average workload per staff (${averageHoursPerStaff.toFixed( 1 )} hours) is above recommended limit.`, action: "Review workload distribution", }); } // Check for payment discrepancies const rpPayment = statistics.rp.total_over_payment || 0; const nrpPayment = statistics.nrp.total_payment || 0; const paymentRatio = rpPayment > 0 ? nrpPayment / rpPayment : 0; if (paymentRatio > 3) { recommendations.push({ type: "financial", title: "NRP Payment Dominance", message: `NRP payments (${nrpPayment.toLocaleString()} ETB) are significantly higher than RP overpayments (${rpPayment.toLocaleString()} ETB).`, action: "Review payment structures", }); } // Check for draft workloads const draftCount = (statistics.rp.by_status?.draft || 0) + (statistics.nrp.by_status?.draft || 0); if (draftCount > 5) { recommendations.push({ type: "process", title: "Pending Draft Workloads", message: `${draftCount} draft workloads need attention.`, action: "Follow up with staff", }); } // Check for department distribution const departments = statistics.overall.department_count || 0; const staffPerDept = statistics.overall.staff_count > 0 ? statistics.overall.staff_count / departments : 0; if (staffPerDept < 3) { recommendations.push({ type: "resource", title: "Staff Distribution", message: `Average of ${staffPerDept.toFixed( 1 )} staff per department. Consider resource reallocation.`, action: "Review department staffing", }); } return recommendations; } // Export report in different formats static async exportReport(reportData, format = "json") { try { switch (format.toLowerCase()) { case "pdf": // Generate PDF report (simplified - in real app use PDF library) return { format: "pdf", data: this.generatePDFReport(reportData), filename: `workload_report_${ new Date().toISOString().split("T")[0] }.pdf`, }; case "excel": // Generate Excel report return { format: "excel", data: this.generateExcelReport(reportData), filename: `workload_report_${ new Date().toISOString().split("T")[0] }.xlsx`, }; case "csv": // Generate CSV report return { format: "csv", data: this.generateCSVReport(reportData), filename: `workload_report_${ new Date().toISOString().split("T")[0] }.csv`, }; case "json": default: return { format: "json", data: reportData, filename: `workload_report_${ new Date().toISOString().split("T")[0] }.json`, }; } } catch (error) { console.error("Error exporting report:", error); throw new Error(`Failed to export report: ${error.message}`); } } // Generate simplified report formats (for demonstration) static generatePDFReport(data) { // In real implementation, use a PDF library like pdfkit return { message: "PDF export would be implemented with a PDF library", data: JSON.stringify(data, null, 2), }; } static generateExcelReport(data) { // In real implementation, use a library like exceljs return { message: "Excel export would be implemented with exceljs", data: JSON.stringify(data, null, 2), }; } static generateCSVReport(data) { try { // Generate CSV from workload data const rpRows = data.data.rp_workloads.map((w) => ({ Type: "RP", "Course Code": w.course_code, "Staff Name": `${w.first_name} ${w.last_name}`, Department: w.department_name, "Total Hours": w.total_load, Status: w.status, "Created Date": w.created_at, })); const nrpRows = data.data.nrp_workloads.map((w) => ({ Type: "NRP", "Course Code": w.course_code, "Staff Name": `${w.first_name} ${w.last_name}`, Department: w.department_name, "Program Type": w.program_type, "Total Hours": w.total_hours_worked, "Total Payment": w.total_payment, Status: w.status, "Created Date": w.created_at, })); const allRows = [...rpRows, ...nrpRows]; // Create CSV headers const headers = Object.keys(allRows[0] || {}); const csvRows = [headers.join(",")]; // Add data rows allRows.forEach((row) => { const values = headers.map((header) => { const value = row[header]; // Escape quotes and wrap in quotes if contains comma const escaped = String(value || "").replace(/"/g, '""'); return escaped.includes(",") ? `"${escaped}"` : escaped; }); csvRows.push(values.join(",")); }); return csvRows.join("\n"); } catch (error) { console.error("Error generating CSV:", error); return "Error generating CSV report"; } } // Get available semesters for filtering static async getAvailableSemesters() { try { const semesters = await query(` SELECT s.*, ay.year_name, ay.year_code FROM semesters s JOIN academic_years ay ON s.academic_year_id = ay.academic_year_id WHERE s.end_date >= DATE_SUB(NOW(), INTERVAL 1 YEAR) ORDER BY s.start_date DESC `); return semesters; } catch (error) { console.error("Error fetching semesters:", error); return []; } } // Get department statistics static async getDepartmentStatistics(department_id = null) { try { let whereClause = ""; const params = []; if (department_id) { whereClause = "WHERE d.department_id = ?"; params.push(department_id); } const stats = await query( ` SELECT d.department_id, d.department_name, d.department_code, c.college_name, COUNT(DISTINCT sp.staff_id) as total_staff, COUNT(DISTINCT wr.workload_id) as rp_workloads, COUNT(DISTINCT wn.nrp_id) as nrp_workloads, COALESCE(SUM(wr.total_load), 0) as rp_total_hours, COALESCE(SUM(wn.total_hours_worked), 0) as nrp_total_hours, COALESCE(SUM(wr.over_payment_birr), 0) as rp_total_payment, COALESCE(SUM(wn.total_payment), 0) as nrp_total_payment, COUNT(DISTINCT CASE WHEN wr.status = 'finance_approved' THEN wr.workload_id END) as rp_approved, COUNT(DISTINCT CASE WHEN wn.status = 'finance_approved' THEN wn.nrp_id END) as nrp_approved FROM departments d JOIN colleges c ON d.college_id = c.college_id LEFT JOIN staff_profiles sp ON d.department_id = sp.department_id LEFT JOIN workload_rp wr ON sp.staff_id = wr.staff_id LEFT JOIN workload_nrp wn ON sp.staff_id = wn.staff_id ${whereClause} GROUP BY d.department_id, d.department_name, d.department_code, c.college_name ORDER BY d.department_name `, params ); return stats; } catch (error) { console.error("Error fetching department statistics:", error); return []; } } // Get staff performance report static async getStaffPerformanceReport(staff_id, semester_id = null) { try { const params = [staff_id]; let semesterCondition = ""; if (semester_id) { semesterCondition = "AND wr.semester_id = ?"; params.push(semester_id); } const performance = await query( ` SELECT sp.staff_id, CONCAT(sp.first_name, ' ', sp.last_name) as staff_name, sp.employee_id, sp.academic_rank, d.department_name, COUNT(DISTINCT wr.workload_id) as total_rp_workloads, COUNT(DISTINCT wn.nrp_id) as total_nrp_workloads, COALESCE(SUM(wr.total_load), 0) as total_rp_hours, COALESCE(SUM(wn.total_hours_worked), 0) as total_nrp_hours, COALESCE(SUM(wr.over_payment_birr), 0) as total_rp_payment, COALESCE(SUM(wn.total_payment), 0) as total_nrp_payment, COUNT(DISTINCT ca.assignment_id) as total_assignments, ROUND(AVG(wr.total_load), 2) as avg_rp_hours_per_workload, ROUND(AVG(wn.total_hours_worked), 2) as avg_nrp_hours_per_workload FROM staff_profiles sp JOIN departments d ON sp.department_id = d.department_id LEFT JOIN workload_rp wr ON sp.staff_id = wr.staff_id ${semesterCondition} LEFT JOIN workload_nrp wn ON sp.staff_id = wn.staff_id ${semesterCondition.replace( "wr.", "wn." )} LEFT JOIN course_assignments ca ON sp.staff_id = ca.staff_id AND ca.status = 'accepted' WHERE sp.staff_id = ? GROUP BY sp.staff_id, sp.first_name, sp.last_name, sp.employee_id, sp.academic_rank, d.department_name `, params ); return performance[0] || null; } catch (error) { console.error("Error fetching staff performance:", error); return null; } } } export default WorkloadReportService; // export default WorkloadService; import { query } from "../config/database.js"; class WorkloadService { // Validate workload compliance static async validateWorkloadCompliance(workload) { const { staff_id, academic_rank, total_load, each_section_course_load, number_of_sections, } = workload; // Get rank limits const rankLimits = await this.getRankLimits(academic_rank); // Get current semester's approved workload const currentWorkload = await this.getCurrentWorkloadHours(staff_id); const validation = { status: "compliant", warnings: [], errors: [], compliance: { rank_limits: rankLimits, current_total: currentWorkload, remaining_capacity: rankLimits.max - currentWorkload, }, }; // Check rank limits if (total_load < rankLimits.min) { validation.warnings.push(`Total load (${total_load}) is below minimum requirement (${rankLimits.min}) for ${academic_rank}`); } if (total_load > rankLimits.max) { validation.errors.push(`Total load (${total_load}) exceeds maximum limit (${rankLimits.max}) for ${academic_rank}`); validation.status = "non_compliant"; } // Check course load calculation const calculatedCourseLoad = each_section_course_load * number_of_sections; const reportedCourseLoad = workload.total_course_load || 0; if (Math.abs(calculatedCourseLoad - reportedCourseLoad) > 0.1) { validation.warnings.push(`Course load calculation mismatch. Calculated: ${calculatedCourseLoad}, Reported: ${reportedCourseLoad}`); } // Check total load calculation const calculatedTotal = reportedCourseLoad + (workload.variety_of_course_load || 0) + (workload.research_load || 0) + (workload.community_service_load || 0) + (workload.elip_load || 0) + (workload.hdp_load || 0) + (workload.course_chair_load || 0) + (workload.section_advisor_load || 0) + (workload.advising_load || 0) + (workload.position_load || 0); if (Math.abs(calculatedTotal - total_load) > 0.1) { validation.warnings.push(`Total load calculation mismatch. Calculated: ${calculatedTotal}, Reported: ${total_load}`); } if (validation.errors.length > 0) { validation.status = "non_compliant"; } else if (validation.warnings.length > 0) { validation.status = "needs_review"; } return validation; } // Get rank limits static async getRankLimits(academicRank) { const [rules] = await query( `SELECT MAX(CASE WHEN rule_name = CONCAT('rank_min_', ?) THEN CAST(rule_value AS DECIMAL) END) as min_load, MAX(CASE WHEN rule_name = CONCAT('rank_max_', ?) THEN CAST(rule_value AS DECIMAL) END) as max_load FROM system_rules WHERE rule_type = 'rank_limit' AND (effective_to IS NULL OR effective_to >= CURDATE())`, [academicRank, academicRank] ); return { min: rules.min_load || 0, max: rules.max_load || 0, }; } // Get current workload hours static async getCurrentWorkloadHours(staffId) { const [result] = await query( `SELECT COALESCE(SUM(total_load), 0) as total_hours FROM workload_rp WHERE staff_id = ? AND status IN ('submitted', 'dh_approved', 'dean_approved', 'hr_approved', 'vpaa_approved', 'vpaf_approved', 'finance_approved')`, [staffId] ); return result.total_hours || 0; } // Calculate overload payment static async calculateOverloadPayment(workload) { const { total_load, academic_rank } = workload; const rankLimits = await this.getRankLimits(academic_rank); if (total_load <= rankLimits.max) { return { is_overload: false, overload_hours: 0, overload_rate: 0, overload_payment: 0, }; } // Get overload rate from system rules const [rateRule] = await query( "SELECT rule_value FROM system_rules WHERE rule_name = 'overload_rate' AND rule_type = 'payment'" ); const overloadRate = parseFloat(rateRule?.rule_value) || 450; const overloadHours = total_load - rankLimits.max; return { is_overload: true, overload_hours: overloadHours, overload_rate: overloadRate, overload_payment: overloadHours * overloadRate, }; } // Get workload summary for staff static async getWorkloadSummary(staffId) { const workloads = await query( `SELECT wr.*, s.semester_code, s.semester_name, s.start_date, s.end_date, ay.year_name FROM workload_rp wr JOIN semesters s ON wr.semester_id = s.semester_id JOIN academic_years ay ON s.academic_year_id = ay.academic_year_id WHERE wr.staff_id = ? ORDER BY s.start_date DESC`, [staffId] ); if (!workloads.length) return null; // Calculate statistics const stats = { total_workloads: workloads.length, total_load_hours: workloads.reduce((sum, w) => sum + (w.total_load || 0), 0), average_load: workloads.reduce((sum, w) => sum + (w.total_load || 0), 0) / workloads.length, total_over_payment: workloads.reduce((sum, w) => sum + (w.over_payment_birr || 0), 0), }; return { staff_id: staffId, workloads: workloads.map(w => this.formatWorkloadSummary(w)), statistics: stats, }; } // Format workload summary static formatWorkloadSummary(workload) { return { workload_id: workload.workload_id, semester: workload.semester_name, academic_year: workload.year_name, course_code: workload.course_code, total_load: workload.total_load, over_payment_birr: workload.over_payment_birr, status: workload.status, period: `${workload.start_date} to ${workload.end_date}`, }; } } export default WorkloadService; import RulesModel from "../models/RulesModel.js"; import { sendSuccess, sendError } from "../utils/response.js"; import { RULE_TYPES, PROGRAM_TYPES, ACADEMIC_RANKS } from "../config/constants.js"; class RulesController { // ==================== CRUD OPERATIONS ==================== // Get all system rules with advanced filtering static async getAllRules(req, res) { try { const { page = 1, limit = 50, rule_type, program_type, is_active, rule_name, effective_from, } = req.query; const result = await RulesModel.findAll(parseInt(page), parseInt(limit), { rule_type, program_type, is_active: is_active === "true" ? true : is_active === "false" ? false : undefined, rule_name, effective_from, }); return sendSuccess(res, "System rules retrieved successfully", result); } catch (error) { console.error("Get all rules error:", error); return sendError(res, "Failed to retrieve system rules", 500); } } // Get rule by ID static async getRuleById(req, res) { try { const { id } = req.params; const rule = await RulesModel.findById(parseInt(id)); if (!rule) { return sendError(res, "Rule not found", 404); } // Get history for this rule const history = await RulesModel.getRuleHistory(rule.rule_name); return sendSuccess(res, "Rule retrieved successfully", { rule, history, }); } catch (error) { console.error("Get rule error:", error); return sendError(res, "Failed to retrieve rule", 500); } } // Create a new rule static async createRule(req, res) { try { const { rule_name, rule_value, rule_type, program_type, effective_from, effective_to, description, } = req.body; // Validate required fields if (!rule_name || !rule_value || !rule_type || !effective_from) { return sendError( res, "Rule name, value, type, and effective from date are required", 400 ); } // Validate rule type const validRuleTypes = Object.values(RULE_TYPES); if (!validRuleTypes.includes(rule_type)) { return sendError( res, `Invalid rule type. Must be one of: ${validRuleTypes.join(", ")}`, 400 ); } // Validate program type if provided if (program_type && program_type !== "all") { const validProgramTypes = Object.values(PROGRAM_TYPES); if (!validProgramTypes.includes(program_type)) { return sendError( res, `Invalid program type. Must be one of: ${validProgramTypes.join( ", " )}`, 400 ); } } // Validate rule value if (!RulesModel.validateRuleValue(rule_type, rule_value)) { return sendError(res, `Invalid value for rule type: ${rule_type}`, 400); } // Validate dates if (effective_to && new Date(effective_from) >= new Date(effective_to)) { return sendError( res, "Effective from date must be before effective to date", 400 ); } const rule = await RulesModel.create({ rule_name, rule_value, rule_type, program_type: program_type || null, effective_from, effective_to: effective_to || null, description: description || null, }); return sendSuccess(res, "Rule created successfully", rule, 201); } catch (error) { console.error("Create rule error:", error); return sendError(res, error.message || "Failed to create rule", 400); } } // Update a rule (creates new version if active) static async updateRule(req, res) { try { const { id } = req.params; const updateData = req.body; // Check if rule exists const existingRule = await RulesModel.findById(parseInt(id)); if (!existingRule) { return sendError(res, "Rule not found", 404); } // Validate rule value if provided if (updateData.rule_value !== undefined) { const ruleType = updateData.rule_type || existingRule.rule_type; if (!RulesModel.validateRuleValue(ruleType, updateData.rule_value)) { return sendError( res, `Invalid value for rule type: ${ruleType}`, 400 ); } } // If rule is active and value is changing, create new version if ( existingRule.is_active && updateData.rule_value && updateData.rule_value !== existingRule.rule_value ) { const newRule = await RulesModel.create({ rule_name: existingRule.rule_name, rule_value: updateData.rule_value, rule_type: updateData.rule_type || existingRule.rule_type, program_type: updateData.program_type || existingRule.program_type, effective_from: new Date().toISOString().split("T")[0], effective_to: updateData.effective_to || null, description: updateData.description || existingRule.description, previous_version_id: existingRule.rule_id, }); // Deactivate the old rule await RulesModel.deactivate(existingRule.rule_id); return sendSuccess( res, "New rule version created and activated", newRule ); } // Otherwise, update normally const updatedRule = await RulesModel.update(parseInt(id), updateData); return sendSuccess(res, "Rule updated successfully", updatedRule); } catch (error) { console.error("Update rule error:", error); return sendError(res, error.message || "Failed to update rule", 400); } } // Delete a rule static async deleteRule(req, res) { try { const { id } = req.params; const existingRule = await RulesModel.findById(parseInt(id)); if (!existingRule) { return sendError(res, "Rule not found", 404); } if (existingRule.is_active) { return sendError( res, "Cannot delete active rule. Deactivate it first.", 400 ); } await RulesModel.delete(parseInt(id)); return sendSuccess(res, "Rule deleted successfully"); } catch (error) { console.error("Delete rule error:", error); return sendError(res, "Failed to delete rule", 500); } } // Activate a rule static async activateRule(req, res) { try { const { id } = req.params; const existingRule = await RulesModel.findById(parseInt(id)); if (!existingRule) { return sendError(res, "Rule not found", 404); } if (existingRule.is_active) { return sendError(res, "Rule is already active", 400); } const activatedRule = await RulesModel.activate(parseInt(id)); return sendSuccess(res, "Rule activated successfully", activatedRule); } catch (error) { console.error("Activate rule error:", error); return sendError(res, "Failed to activate rule", 500); } } // Deactivate a rule static async deactivateRule(req, res) { try { const { id } = req.params; const deactivatedRule = await RulesModel.deactivate(parseInt(id)); return sendSuccess(res, "Rule deactivated successfully", deactivatedRule); } catch (error) { console.error("Deactivate rule error:", error); return sendError(res, "Failed to deactivate rule", 500); } } // ==================== BUSINESS LOGIC OPERATIONS ==================== // Evaluate a rule static async evaluateRule(req, res) { try { const { rule_name, program_type = null, context = {} } = req.body; if (!rule_name) { return sendError(res, "Rule name is required", 400); } const result = await RulesModel.evaluate( rule_name, program_type, context ); return sendSuccess(res, "Rule evaluated successfully", result); } catch (error) { console.error("Evaluate rule error:", error); return sendError(res, error.message || "Failed to evaluate rule", 400); } } // Calculate load with factors static async calculateLoad(req, res) { try { const { lecture_hours, lab_hours = 0, tutorial_hours = 0, program_type = "regular", } = req.body; if (!lecture_hours && lecture_hours !== 0) { return sendError(res, "Lecture hours are required", 400); } const result = await RulesModel.calculateLoad( parseFloat(lecture_hours), parseFloat(lab_hours), parseFloat(tutorial_hours), program_type ); return sendSuccess(res, "Load calculated successfully", result); } catch (error) { console.error("Calculate load error:", error); return sendError(res, error.message || "Failed to calculate load", 400); } } // Validate rank load static async validateRankLoad(req, res) { try { const { rank, total_hours, program_type = "regular" } = req.body; if (!rank || total_hours === undefined) { return sendError(res, "Rank and total hours are required", 400); } const result = await RulesModel.validateRankLoad( rank, parseFloat(total_hours), program_type ); return sendSuccess(res, "Rank load validation completed", result); } catch (error) { console.error("Validate rank load error:", error); return sendError( res, error.message || "Failed to validate rank load", 400 ); } } // Calculate NRP payment static async calculateNRPPayment(req, res) { try { const { program_type, rate_category = "default", credit_hours, student_count = 0, } = req.body; if (!program_type || !credit_hours) { return sendError( res, "Program type and credit hours are required", 400 ); } const result = await RulesModel.calculateNRPPayment( program_type, rate_category, parseFloat(credit_hours), parseInt(student_count) ); return sendSuccess(res, "NRP payment calculated", result); } catch (error) { console.error("Calculate NRP payment error:", error); return sendError( res, error.message || "Failed to calculate NRP payment", 400 ); } } // Calculate overload payment static async calculateOverloadPayment(req, res) { try { const { overload_hours } = req.body; if (!overload_hours || overload_hours <= 0) { return sendError(res, "Valid overload hours are required", 400); } const result = await RulesModel.calculateOverloadPayment( parseFloat(overload_hours) ); return sendSuccess(res, "Overload payment calculated", result); } catch (error) { console.error("Calculate overload payment error:", error); return sendError( res, error.message || "Failed to calculate overload payment", 400 ); } } // Get correction rates static async getCorrectionRates(req, res) { try { const rates = await RulesModel.getCorrectionRates(); return sendSuccess(res, "Correction rates retrieved", rates); } catch (error) { console.error("Get correction rates error:", error); // Return default values if rules don't exist const defaultRates = { assignment: 10, exam: 15, tutorial: 150, }; return sendSuccess(res, "Correction rates retrieved (default)", defaultRates); } } // Apply summer distribution static async applySummerDistribution(req, res) { try { const { total_payment } = req.body; if (!total_payment || total_payment <= 0) { return sendError(res, "Valid total payment amount is required", 400); } const result = await RulesModel.applySummerDistribution( parseFloat(total_payment) ); return sendSuccess(res, "Summer distribution applied", result); } catch (error) { console.error("Apply summer distribution error:", error); // Return default distribution const defaultDistribution = { total: parseFloat(total_payment).toFixed(2), stage1: parseFloat((total_payment * 0.3).toFixed(2)), stage2: parseFloat((total_payment * 0.3).toFixed(2)), stage3: parseFloat((total_payment * 0.2).toFixed(2)), stage4: parseFloat((total_payment * 0.2).toFixed(2)), distribution: { stage1: 30.0, stage2: 30.0, stage3: 20.0, stage4: 20.0, }, }; return sendSuccess(res, "Summer distribution applied (default)", defaultDistribution); } } // ==================== UTILITY OPERATIONS ==================== // Get rule by name static async getRuleByName(req, res) { try { const { name } = req.params; const { program_type } = req.query; const rule = await RulesModel.findActiveRuleByName(name, program_type); if (!rule) { return sendError(res, `Rule '${name}' not found`, 404); } return sendSuccess(res, "Rule retrieved successfully", rule); } catch (error) { console.error("Get rule by name error:", error); return sendError(res, "Failed to retrieve rule", 500); } } // Get rules by type static async getRulesByType(req, res) { try { const { type } = req.params; const { program_type, active_only = "true" } = req.query; const validRuleTypes = Object.values(RULE_TYPES); if (!validRuleTypes.includes(type)) { return sendError( res, `Invalid rule type. Must be one of: ${validRuleTypes.join(", ")}`, 400 ); } const rules = await RulesModel.findByType( type, program_type, active_only === "true" ); return sendSuccess(res, `Rules of type ${type} retrieved`, rules); } catch (error) { console.error("Get rules by type error:", error); return sendError(res, "Failed to retrieve rules by type", 500); } } // Get rule history static async getRuleHistory(req, res) { try { const { name } = req.params; const history = await RulesModel.getRuleHistory(name); return sendSuccess(res, "Rule history retrieved", history); } catch (error) { console.error("Get rule history error:", error); return sendError(res, "Failed to retrieve rule history", 500); } } // Get rank load limits static async getRankLoadLimits(req, res) { try { const { rank } = req.params; const { program_type = "regular" } = req.query; const limits = await RulesModel.getRankLimits(rank, program_type); return sendSuccess(res, "Rank load limits retrieved", { rank, program_type, ...limits, }); } catch (error) { console.error("Get rank load limits error:", error); // Return null values if rules don't exist return sendSuccess(res, "Rank load limits retrieved", { rank, min: null, max: null, }); } } // Get all rank load limits static async getAllRankLoadLimits(req, res) { try { const { program_type = "regular" } = req.query; const limits = await RulesModel.getAllRankLoadLimits(program_type); return sendSuccess(res, "All rank load limits retrieved", limits); } catch (error) { console.error("Get all rank load limits error:", error); // Return empty object if error return sendSuccess(res, "All rank load limits retrieved", {}); } } // Get load factors static async getLoadFactors(req, res) { try { const { program_type = "regular" } = req.query; const factors = await RulesModel.getLoadFactors(program_type); return sendSuccess(res, "Load factors retrieved", factors); } catch (error) { console.error("Get load factors error:", error); // Return default factors const defaultFactors = { lab: 0.75, tutorial: 0.5, lecture: 1.0, module_distance: 1.0, }; return sendSuccess(res, "Load factors retrieved (default)", defaultFactors); } } // Get payment rates static async getPaymentRates(req, res) { try { const { program_type } = req.params; const { rate_category } = req.query; const rates = await RulesModel.getPaymentRate( program_type, rate_category ); return sendSuccess(res, "Payment rates retrieved", rates || {}); } catch (error) { console.error("Get payment rates error:", error); return sendSuccess(res, "Payment rates retrieved", {}); } } // Get summer distribution static async getSummerDistribution(req, res) { try { const distribution = await RulesModel.getSummerDistribution(); return sendSuccess(res, "Summer distribution retrieved", distribution); } catch (error) { console.error("Get summer distribution error:", error); // Return default distribution const defaultDistribution = { stage1: 30.0, stage2: 30.0, stage3: 20.0, stage4: 20.0, }; return sendSuccess(res, "Summer distribution retrieved (default)", defaultDistribution); } } // Bulk update rules static async bulkUpdateRules(req, res) { try { const { rules } = req.body; if (!rules || !Array.isArray(rules) || rules.length === 0) { return sendError(res, "Rules array is required", 400); } const results = await RulesModel.bulkUpdate(rules); return sendSuccess(res, "Rules updated successfully", results); } catch (error) { console.error("Bulk update rules error:", error); return sendError(res, "Failed to update rules", 500); } } // Validate workload static async validateWorkload(req, res) { try { const workloadData = req.body; if (!workloadData.staff_id) { return sendError(res, "Staff ID is required", 400); } const validation = await RulesModel.validateWorkload(workloadData); return sendSuccess(res, "Workload validation completed", validation); } catch (error) { console.error("Validate workload error:", error); return sendError( res, error.message || "Failed to validate workload", 400 ); } } // Get rules dashboard static async getRulesDashboard(req, res) { try { const dashboard = await RulesModel.getDashboardSummary(); return sendSuccess(res, "Rules dashboard retrieved", dashboard); } catch (error) { console.error("Get rules dashboard error:", error); return sendError(res, "Failed to get rules dashboard", 500); } } // Clear cache (admin only) static async clearCache(req, res) { try { RulesModel.clearCache(); return sendSuccess(res, "Rules cache cleared"); } catch (error) { console.error("Clear cache error:", error); return sendError(res, "Failed to clear cache", 500); } } // Get active rate tables static async getActiveRateTables(req, res) { try { const { program_type } = req.query; const rates = await RulesModel.getActiveRateTables(program_type); return sendSuccess(res, "Active rate tables retrieved", rates); } catch (error) { console.error("Get active rate tables error:", error); return sendError(res, "Failed to get rate tables", 500); } } // Get active tax rules static async getActiveTaxRules(req, res) { try { const { program_type } = req.query; const taxRules = await RulesModel.getActiveTaxRules(program_type); return sendSuccess(res, "Active tax rules retrieved", taxRules); } catch (error) { console.error("Get active tax rules error:", error); return sendError(res, "Failed to get tax rules", 500); } } } export default RulesController;import express from "express"; import OverloadDetectionController from "../controllers/OverloadDetectionController.js"; // import { authenticate, authorize } from "../middleware/auth.js"; import { auth as authenticate, requireRole as authorize, } from "../middleware/auth.js"; const router = express.Router(); // All routes require authentication router.use(authenticate); // Instructor routes router.get("/my", authorize("instructor"), OverloadDetectionController.checkMyOverload); // Department Head routes router.get("/department/:departmentId/:semesterId", authorize("department_head",